INSERT INTO `occupation` VALUES (97, '财务总监', '[\"会计学\", \"财务管理\", \"MBA\"]', '[\"财务战略\", \"资本运作\", \"财务分析\", \"全面预算\", \"团队管理\", \"上市合规\"]', 'A', 'IEC型', '企业核心高管，战略决策参与者，职业天花板极高，薪资与股权激励丰厚', '2025-11-15 23:44:56');
INSERT INTO `occupation` VALUES (98, '投资银行家', '[\"金融学\", \"法学\", \"MBA\"]', '[\"IPO并购融资\", \"估值建模\", \"交易结构设计\", \"客户关系\", \"监管沟通\"]', 'A', 'SEC型', '资本市场的顶级玩家，交易规模大，职业声望高，薪资天花板极高', '2025-11-15 23:44:56');
INSERT INTO `occupation` VALUES (99, '风险投资家', '[\"金融学\", \"MBA\", \"产业背景\"]', '[\"行业趋势判断\", \"项目尽调估值\", \"投资组合管理\", \"投后管理\", \"退出策略\"]', 'A', 'SEC型', '站在创新经济前沿，投资决策影响力大，成功项目回报巨大，职业自由度极高', '2025-11-15 23:44:56');
INSERT INTO `occupation` VALUES (100, '私募股权分析师', '[\"金融学\", \"会计学\", \"MBA\"]', '[\"财务建模\", \"杠杆收购\", \"投后价值创造\", \"行业研究\", \"基金募集\", \"投资者关系\"]', 'A', 'IRC型', '深度参与企业价值创造，技术财务双重要求，职业成长快，薪资加Carry丰厚', '2025-11-15 23:44:56');
INSERT INTO `policy_data` VALUES (1, '《2025年高校毕业生\"三支一扶\"计划》', '三支一扶、2025招募、中央财政支持', '明确中央财政支持招募34430名高校毕业生到基层从事支教、支农、支医和帮扶乡村振兴服务，要求各地优化招募选拔流程，扩大招募规模并向脱贫地区、西部地区、东北地区、革命老区、民族地区和边疆地区倾斜，对口支援省市协助西藏、新疆招募，强化能力提升与管理使用，规范管理使用基层服务单位，落实待遇保障，加强日常管理与联系服务，拓展留用渠道落实机关事业单位考录支持政策，鼓励服务期满人员留当地工作并纳入人才工作部署跟踪培养，加强组织领导并严格财经纪律', '2025-11-16 21:07:20', '2025-11-16 21:07:20');
INSERT INTO `policy_data` VALUES (2, '《2025年高校毕业生\"三支一扶\"计划》', '支教岗位、师范专业、基层教育', '支教岗位面向汉语言文学、数学与应用数学、英语、物理学、化学、生物学、历史学、地理科学、思想政治教育、音乐学、美术学、体育教育等师范类专业毕业生，中央财政支持8000人次能力提升专项培训，基层服务单位需加强培养使用，落实待遇保障，强化日常管理与联系服务，服务期满可落实机关事业单位考录支持政策，鼓励留当地工作，纳入人才跟踪培养体系', '2025-11-16 21:07:20', '2025-11-16 21:07:20');
INSERT INTO `policy_data` VALUES (3, '《2025年高校毕业生\"三支一扶\"计划》', '支农岗位、农业专业、乡村振兴', '支农岗位面向农学、园艺、植物保护、农业资源与环境、动物科学、动物医学、林学、园林、农业机械化及其自动化等农业类专业毕业生，中央财政支持8000人次专项培训，培训体系围绕基层需求确定重点，完善分层分类培训，服务期满可落实机关事业单位考录支持政策，鼓励留当地工作，拓展留用渠道，支持创新创业', '2025-11-16 21:07:20', '2025-11-16 21:07:20');
INSERT INTO `policy_data` VALUES (4, '《2025年高校毕业生\"三支一扶\"计划》', '支医岗位、医学专业、基层医疗', '支医岗位面向临床医学、中医学、针灸推拿学、护理学、药学、医学检验技术、医学影像学等医学类专业毕业生，基层服务单位落实待遇保障，加强日常管理，服务期满纳入人才工作部署跟踪培养，鼓励服务期满人员留当地工作，拓宽职业成长空间，落实编制政策，强化日常联系服务', '2025-11-16 21:07:20', '2025-11-16 21:07:20');
INSERT INTO `policy_data` VALUES (5, '《2025年高校毕业生\"三支一扶\"计划》', '乡村振兴、经济管理类、乡村治理', '帮扶乡村振兴岗位面向经济学类（农村区域发展、农林经济管理）、公共管理类（行政管理、土地资源管理）、社会学类（社会工作）等专业毕业生参与乡村产业发展与治理，拓展留用渠道支持创新创业，纳入人才工作部署跟踪培养，加强政策宣传与典型经验总结，提升宣传效果', '2025-11-16 21:07:20', '2025-11-16 21:07:20');
INSERT INTO `policy_data` VALUES (6, '《2025年高校毕业生\"三支一扶\"计划》', '服务期满、编制政策、留用渠道', '明确服务期满人员可落实机关事业单位考录、招聘支持政策，拓宽基层留人用人渠道，鼓励服务期满人员留当地工作，符合条件的纳入人才工作部署跟踪培养，加强政策宣传与典型经验总结，提升宣传效果，强化多方协同，加快实施进度', '2025-11-16 21:07:20', '2025-11-16 21:07:20');
INSERT INTO `policy_data` VALUES (7, '《2025年高校毕业生\"三支一扶\"计划》', '能力提升、专项培训、分层分类', '中央财政支持8000人次能力提升专项培训，围绕基层需求确定培训重点，完善分层分类培训体系，基层服务单位加强培养使用，强化日常管理与联系服务，提高培训精准性，多方筹集资金，健全市场化投入机制，鼓励社会资本投入', '2025-11-16 21:07:20', '2025-11-16 21:07:20');
INSERT INTO `policy_data` VALUES (8, '《\"十四五\"职业技能培训规划》', '职业培训、7500万人次、补贴性培训', '提出到2025年组织实施政府补贴性培训7500万人次以上，其中农民工职业技能培训3000万人次以上，新增取得职业资格或技能等级证书人员4000万人次以上，新增公共实训基地200个，完善终身职业技能培训制度，健全共建共享培训体系，提升培训有效性，加强标准化建设，加强统筹规划与组织领导', '2025-11-16 21:07:20', '2025-11-16 21:07:20');
INSERT INTO `policy_data` VALUES (9, '《\"十四五\"职业技能培训规划》', '高技能人才、800万人次、公共实训基地', '目标新增高技能人才800万人次以上，新增公共实训基地200个，完善技能人才职业发展通道，探索\"新八级\"职业技能等级制度，实现技能人才横向贯通发展，推出完善评价体系等措施，提高待遇水平，营造良好社会导向，让职业技能培训扩容提质', '2025-11-16 21:07:20', '2025-11-16 21:07:20');
INSERT INTO `policy_data` VALUES (10, '《\"十四五\"职业技能培训规划》', '新八级工、职业发展、横向贯通', '探索\"新八级\"职业技能等级制度，实现技能人才纵向职业技能等级阶梯与专业技术人才横向贯通发展，完善技能人才评价体系，为技术工人突破职业发展天花板创造条件，提高技能劳动者待遇水平，拓展职业发展通道，营造良好社会导向', '2025-11-16 21:07:20', '2025-11-16 21:07:20');
INSERT INTO `policy_data` VALUES (11, '《\"十四五\"职业技能培训规划》', '产训结合、企业主体、精准培训', '首次提出产训结合理念与举措，强调发挥企业培训主体作用，提高院校培训针对性，促进培训机构健康发展，发挥公共实训基地基础支撑作用，围绕产业和企业需求开展精准培训，营造良好社会导向，提高劳动者待遇，提升培训供给能力', '2025-11-16 21:07:20', '2025-11-16 21:07:20');
INSERT INTO `policy_data` VALUES (12, '《\"十四五\"职业技能培训规划》', '数字技能、新职业培训、职业分类大典', '从修订职业分类大典标注数字技能类职业、开发培训标准教材、推进数字技能职业技能等级认定、推动数字技能相关比赛、培育数字技能培训基地等五个方面助力新经济职业培训，适应数字经济发展，加强数字技能人才培养，完善数字技能评价体系，推动数字技能普及', '2025-11-16 21:07:20', '2025-11-16 21:07:20');
INSERT INTO `policy_data` VALUES (13, '《\"十四五\"职业技能培训规划》', '制造业技能、机械专业培训、高级技工', '面向机械设计制造及其自动化、材料成型及控制工程、工业工程等专业学生开展职业技能培训，向高级技工、技师方向发展，满足制造业对高层次技能人才需求，提升实操技能，产训结合提高精准性，发挥公共实训基地作用，鼓励企业主体参与培训，提升培训供给能力', '2025-11-16 21:07:20', '2025-11-16 21:07:20');
INSERT INTO `policy_data` VALUES (14, '《\"十四五\"职业技能培训规划》', '信息技术、大数据培训、物联网', '面向计算机科学与技术、软件工程、大数据技术等专业学生开展数字技能培训，依据新修订的职业分类大典及开发的培训标准，提升在大数据、物联网等领域的数字技能，适应新经济需求，推进等级认定和培训基地建设，培育数字技能人才队伍，加强数字技能职业标准开发，推动数字技能相关比赛', '2025-11-16 21:07:20', '2025-11-16 21:07:20');
INSERT INTO `policy_data` VALUES (15, '《\"十四五\"职业技能培训规划》', '职教教师、师资培养、培训供给能力', '支持职业技术教育等相关专业大学生学习先进培训理念与方法，参与高质量职业技能培训教学工作，提升培训供给能力，减少低端培训，增加中高端培训，培育专业师资队伍，鼓励社会资本投入，健全市场化机制，加强培训标准化建设，提高培训质量，动态调整培训专业设置补贴项目', '2025-11-16 21:07:20', '2025-11-16 21:07:20');
INSERT INTO `policy_data` VALUES (16, '《\"十四五\"职业技能培训规划》', '应用型专业、产训结合、就业创业', '面向物流管理、电子商务、酒店管理等应用型专业学生，结合产训结合理念围绕产业发展需求进行职业技能培训，提高就业创业能力，实现技能成才，促进培训机构健康发展，营造良好社会导向，提高劳动者待遇，加强标准化建设，提升培训有效性，完善共建共享培训体系', '2025-11-16 21:07:20', '2025-11-16 21:07:20');
INSERT INTO `policy_data` VALUES (17, '《\"十四五\"职业技能培训规划》', '农民工、培训目标、终身培训', '明确农民工职业技能培训3000万人次以上，健全终身职业技能培训制度，提升培训服务有效性，加强标准化建设，完善共建共享培训体系，发挥公共实训基地基础支撑作用，多方筹集资金，统筹就业补助资金，严格财经纪律，加强组织领导，开展总结评估，注重高层次技能人才培训', '2025-11-16 21:07:20', '2025-11-16 21:07:20');
INSERT INTO `policy_data` VALUES (18, '《\"十四五\"职业技能培训规划》', '技能评价、证书体系、等级认定', '新增取得职业资格或技能等级证书人员4000万人次以上，完善技能人才评价体系，推进数字技能职业技能等级认定，加强技能人才队伍建设，推动相关技能竞赛，提高培训质量，加强标准化建设，完善技能人才职业发展通道，探索技能人才与专业技术人才横向贯通发展，推出完善评价体系措施', '2025-11-16 21:07:20', '2025-11-16 21:07:20');
INSERT INTO `policy_data` VALUES (19, '《\"十四五\"职业技能培训规划》', '培训资金、就业补助、社会资本', '统筹利用就业补助资金，健全市场化投入机制，鼓励社会资本投入，加强资金监管和绩效评估，多方筹集资金，加强统筹规划与组织领导，开展总结评估并加强工作交流，严格财经纪律，注重高层次技能人才培训，动态调整培训专业设置补贴项目，加强标准化建设', '2025-11-16 21:07:20', '2025-11-16 21:07:20');
INSERT INTO `policy_data` VALUES (20, '《\"十四五\"职业技能培训规划》', '待遇提高、激励政策、社会导向', '强调提高技能劳动者待遇水平，营造良好社会氛围，让职业技能培训真正扩容提质，拓展职业发展通道，为技术工人向特级技师等更高层级发展创造条件，加强标准化建设，提升培训供给能力，减少低端培训，增加中高端培训，实现技能成才目标，加强政策宣传，提高培训质量', '2025-11-16 21:07:20', '2025-11-16 21:07:20');
INSERT INTO `policy_data` VALUES (21, '人力资源社会保障部办公厅 财政部办公厅关于做好2025年高校毕业生“三支一扶”计划实施工作的通知', '毕业生、创业、高校毕业生、就业、三支一扶、招聘、补贴、贷款、培训', '来源：中国政府网\n发文机关：人力资源社会保障部办公厅 财政部办公厅\n发文字号：人社厅发〔2025〕21号\n原文链接：https://www.gov.cn/zhengce/zhengceku/202505/content_7025914.htm\n\n人力资源社会保障部办公厅 财政部办公厅关于做好2025年高校毕业生“三支一扶”计划实施工作的通知\n人社厅发〔2025〕21号\n各省、自治区、直辖市及新疆生产建设兵团人力资源社会保障厅（局）、财政厅（局），上海市人才工作局：\n按照《中共中央组织部 人力资源社会保障部等十部门关于实施第四轮高校毕业生“三支一扶”计划的通知》（人社部发〔2021〕32号）有关要求，2025年继续招募选拔高校毕业生到基层从事“三支一扶”（支教、支农、支医和帮扶乡村振兴）服务。现就做好有关工作通知如下。\n一、优化招募选拔。2025年中央财政支持招募“三支一扶”人员34430名，各地可结合实际适当扩大招募规模，加力服务岗位扩容挖潜。要突出重点科学制定招募方案，持续优化招募人员结构。聚焦助力乡村全面振兴需要，持续加大对脱贫地区支持力度，对国家乡村振兴重点帮扶县实行计划单列，积极拓展农技推广、农村医疗服务、水利基础设施建设与运行管理、生态保护修复和乡村建设治理等岗位开发。聚焦西部大开发、东北全面振兴等战略部署，持续加大对西部地区、东北地区支持力度，进一步加大对革命老区、民族地区和边疆地区支持力度。落实进一步吸引内地优秀高校毕业生等进藏工作相关政策措施，支持西藏适当扩大人员招募规模、优化人员招募结构、增强人岗匹配度。依托现有对口支援关系，对口支援省市要积极配合受援地发布招募公告、组织招募考试，选派优秀高校毕业生到西藏、新疆服务。\n二、强化能力提升。聚力解决高校毕业生服务基层“水土不服”问题，更好实施能力提升专项计划，全面提升“三支一扶”人员参与基层治理能力素质。2025年中央财政支持开展能力提升专项培训8000人次，承接专项培训的省份要制定专门方案，紧扣基层需要，以“千万工程”经验、农业绿色发展、村庄规划、乡情社情、群众工作、乡村建设治理、产业发展等为培训重点，提升培训针对性、实效性。加强专业能力培训，将“三支一扶”人员纳入教育、医疗卫生、水利、农业农村、林草等基层专业人才培训体系，支持参加继续教育、学习进修、考察调研等行业性培训活动。健全分层分类培训体系，各地要结合实际不断完善岗前、在岗、离岗等培训，拓展行业领域专业培训，严肃培训纪律，提升培训质量，构建覆盖全服务周期的教育培训制度。\n三、规范管理使用。更好发挥基层服务单位主体作用，加强“三支一扶”人员培养使用，完善导师帮带机制，择优推荐到重点岗位历练，参与基层重大项目建设和重点任务，不断提升基层工作本领。落实待遇保障，按规定及时足额发放工作生活补贴和一次性安家费，落实参加社会保险政策和艰苦边远地区津贴，鼓励各地结合实际健全激励机制，提高待遇保障水平。强化日常管理和联系服务，依托工作管理信息系统，加强在岗情况检查和管理，定期组织走访慰问、座谈交流等活动，及时掌握“三支一扶”人员思想动态，帮助解决工作生活中的困难问题，激发基层安心干事创业热情。\n四、拓展留用渠道。积极推动机关事业单位定向考录、专项招聘和同等条件下优先聘用等支持政策更好落实，稳妥衔接规范事业单位公开招聘倾斜政策工作。落实住院医师规范化培训、升学深造、学费补偿和助学贷款代偿等政策。加力拓宽基层留人用人渠道，深入挖掘国有企业、规上企业等优质岗位，组织优质人力资源服务机构提供针对性服务，公共就业和人才服务机构要对就业困难的提供“一对一”就业帮扶。支持基层创新创业，鼓励引导因地制宜投身乡村特色产业发展，强化创业培训、技术指导、项目配套、金融保险等支持，按规定给予一次性创业补贴，落实相关税收优惠政策。\n五、加大西部地区引才留才工作力度。西部省份县乡事业单位要适当增加专项招聘服务期满考核合格“三支一扶”人员的岗位数量，并增加工作实绩在考察中的权重，聘用后可以不再约定试用期。要用好用足艰苦边远地区基层事业单位公开招聘“三放宽一允许”倾斜政策，对招聘符合条件的服务期满考核合格“三支一扶”人员的岗位，可以根据实际情况采取面试、组织考察等方式公开招聘。西藏、新疆及四省涉藏州县要按照相关规定完善和落实定向考录（专项招聘）政策，积极鼓励引导服务期满人员留在当地工作，继续扎根基层、服务群众。\n六、加强跟踪培养。进一步完善政策措施，建立健全人社厅发〔2025〕21号联系服务工作台账，动态跟踪和持续培养服务期满“三支一扶”人员更好成长。推动将“三支一扶”计划纳入当地人才工作总体部署，按规定纳入当地引进人才目录、后备人才目录等，落实有关支持政策。拓宽职业成长空间，落实县以下职称“定向评价、定向使用”政策，对长期扎根基层且做出重要贡献的“三支一扶”人员可破格申报职称。对在基层表现优秀的服务期满人员，按照国家有关规定积极推荐纳入相关表彰奖励项目。\n七、加大宣传引导力度。加强典型宣传，跟进“报效祖国 建功西部”系列宣传，深入报道优秀“三支一扶”人员先进事迹和基层服务单位典型做法，积极营造高校毕业生扎根基层、成长成才的良好氛围。深化政策解读，深入宣传中央鼓励支持高校毕业生到基层工作的方针政策，积极推动“三支一扶”计划政策解读进校园进基层。及时总结经验做法，广泛宣传“三支一扶”计划的重要意义和实施成效，进一步拓宽宣传渠道，创新宣传方式，不断提升宣传效果。\n八、加强组织领导。各地要高度重视，强化部门协同，充分发挥职能优势，完善相关政策措施，扎实做好年度组织实施工作。加快实施进度，确保8月底前完成招募选拔，9月上旬招募人员上岗服务。严格财经纪律，从严管理使用中央财政补助资金，按要求开展绩效自评、据实结算和资金申请等工作，提高资金使用效率。2025年是第四轮“三支一扶”计划的收官之年，要认真开展第四轮计划总结评估工作，全面评估实施成效和存在问题，系统谋划新一轮计划创新举措，于10月底前完成自评工作并报送评估报告。加强工作交流，相关信息和建议可反馈人力资源社会保障部人力资源流动管理司。\n人力资源社会保障部办公厅\n财政部办公厅\n2025年5月26日', '2026-04-26 01:42:36', '2026-04-26 02:11:02');
INSERT INTO `policy_data` VALUES (22, '如何招募，有何变化?——解读2025年“三支一扶”计划', '毕业生、创业、大学生、高校毕业生、就业、三支一扶、自主创业、招聘、补贴、贷款、培训', '来源：新华社\n原文链接：https://www.gov.cn/zhengce/202505/content_7025870.htm\n\n新华社北京5月30日电 题：如何招募，有何变化？——解读2025年“三支一扶”计划\n新华社“新华视点”记者 姜琳、李雄鹰\n为进一步促进高校毕业生就业，人力资源社会保障部近日会同有关部门实施2025年“三支一扶”计划，在全国招募34430名高校毕业生到基层从事支教、支农、支医和帮扶乡村振兴等服务。\n截至目前，已有北京、天津、山西、内蒙古、黑龙江、安徽、福建、江西等15个省份发布了招募公告。各地有多少名额？今年招录政策有何变化？有何待遇保障？“新华视点”记者采访了权威部门。\n重点支持哪些地区？招募工作如何开展？\n“三支一扶”计划，是政府引导鼓励高校毕业生到基层工作的示范项目，服务期为2年。与大学生志愿服务西部计划不同，“三支一扶”是在哪个省报考，就在哪个省的基层服务。\n人力资源社会保障部人力资源流动管理司负责人介绍，今年招募选拔工作继续服务国家战略，向脱贫地区、西部地区、东北地区等倾斜。例如中央财政支持的西部地区招募名额逐年增加，今年占比达到55.9%。\n此外，今年“三支一扶”计划首次提出，依托现有对口支援关系，由对口支援省市积极配合受援地发布招募公告、组织招募考试，选派优秀高校毕业生到西藏、新疆服务。\n据记者了解，在中央财政招募名额基础上，部分省份通过地方财政支持，扩大了招募规模。目前已发布“三支一扶”计划招募公告的省份中，内蒙古、河南和广东招募人数均达到3000人。\n从报考条件看，大部分省份将年龄上限设置为30周岁，将毕业年限放宽至毕业三年内，云南、内蒙古允许四年内毕业生报名。重庆等地为报考户籍所在服务岗位的零就业家庭子女、城乡低保家庭子女、本人残疾的考生开辟绿色通道。\n记者注意到，为加快推进高校毕业生就业，今年多地组织“三支一扶”报名考试的时间较往年有所提前。截至目前，贵州、北京、重庆、湖北等11个省份已完成笔试。除广东、江西等少数省份根据笔试成绩直接确定招募对象外，其余省份将于6月中下旬至7月组织开展面试。\n记者从人力资源社会保障部获悉，按照相关部署要求，各省须确保8月底前完成招募选拔，9月上旬新招募人员上岗服务。\n基层岗位保障如何？今年有哪些新变化？\n“三支一扶”计划具体包括哪些岗位？据介绍，毕业生一般安排在乡镇基层单位服务。各地将择优推荐担任基层单位团委副书记、河（湖、林）长助理、农业技术服务站（所）长助理、林场（站）长助理、基层供销社主任助理等。\n那么，到基层服务待遇如何，有哪些保障？\n根据今年“三支一扶”计划实施要求，各地需按规定及时足额发放工作生活补贴和一次性安家费，落实参加社会保险政策和艰苦边远地区津贴。\n“三支一扶”人员的工作生活补贴标准，按照当地乡镇机关或事业单位从高校毕业生中新聘用人员转正后的工资水平确定。中央财政按照东部地区每人每年1.2万元、中部地区2.4万元、西部地区3万元（西藏、新疆南疆四地州4万元）和一次性安家费每人3000元的标准给予补助。相关部门持续鼓励各地结合实际健全激励机制，提高待遇保障水平。此外，基层用人单位还会提供食宿、交通等便利。\n除了待遇，今年到基层支教、支农、支医和帮扶乡村振兴，还有哪些新变化？\n人力资源社会保障部表示，将更加突出“培训”二字。\n2025年中央财政将支持开展“三支一扶”人员能力提升专项培训8000人次，以“千万工程”经验、农业绿色发展、村庄规划、乡情社情、群众工作、乡村建设治理、产业发展等为培训重点，全面提升毕业生参与基层治理的适应性和服务水平。\n专业能力培训也是今年一大重点。各地将把“三支一扶”人员纳入教育、医疗卫生、水利、农业农村、林草等基层专业人才培训体系，支持参加继续教育、学习进修、考察调研等行业性培训活动。\n服务期满能得到哪些政策支持？\n2025年是第四轮“三支一扶”计划的收官之年。4年来，全国已选派16.5万名毕业生到基层服务。\n不仅鼓励“下得去、留得住”，还要支持“干得好、流得动”。\n人社部门强调，各地应对服务期满留在基层的人员，在职称评定、进修学习、人才项目选拔等方面优先支持，对在基层表现优秀的按规定积极推荐纳入相关表彰奖励项目。\n根据规定，服务期满且考核合格人员，3年内参加全国硕士研究生招生考试初试总分加10分，同等条件下优先录取。2年内在参加机关事业单位考录（招聘）、各类企业吸纳就业、自主创业等方面同等享受应届高校毕业生相关政策。\n人力资源社会保障部人力资源流动管理司负责人表示，毕业生经过两年锻炼，熟悉基层情况，对群众工作方法有所掌握，留在基层能很快适应工作。促进期满人员流动发展的主要政策取向，是畅通基层服务单位留用渠道，促进更多“三支一扶”人员扎根基层。\n今年“三支一扶”计划要求各地积极推动机关事业单位定向考录、专项招聘等支持政策更好落实；落实住院医师规范化培训、升学深造、学费补偿和助学贷款代偿等政策；深入挖掘国有企业、规上企业等优质岗位，支持基层创新创业，促进期满人员多渠道就业。\n按规定，各地省级以下公务员考试拿出考录计划的10%左右，定向招录“三支一扶”计划等服务基层项目人员。县乡基层事业单位拿出一定数量岗位，对“三支一扶”服务期满考核合格的人员进行专项招聘。省市事业单位公开招聘时，同等条件下优先聘用“三支一扶”服务期满考核合格的人员。\n针对西部地区引才留才，今年特别要求西部省份县乡事业单位适当增加专项招聘岗位数量，用好用足“三放宽一允许”倾斜政策，按规定优化公开招聘方式，持续加强跟踪培养，推动服务期满“三支一扶”人员扎根西部成长成才。', '2026-04-26 01:42:36', '2026-04-26 02:11:02');
INSERT INTO `policy_data` VALUES (23, '人力资源社会保障部 教育部 财政部关于做好高校毕业生等青年就业创业工作的通知', '毕业生、创业、高校毕业生、就业、基层就业、三支一扶、自主创业、灵活就业、招聘、补贴、贷款、培训、见习、青年就业', '来源：中国政府网\n发文机关：人力资源社会保障部 教育部 财政部\n发文字号：人社部发〔2024〕44号\n原文链接：https://www.gov.cn/zhengce/zhengceku/202406/content_6958297.htm\n\n人力资源社会保障部 教育部 财政部关于做好高校毕业生等青年就业创业工作的通知\n人社部发〔2024〕44号\n各省、自治区、直辖市及新疆生产建设兵团人力资源社会保障厅（局）、教育厅（教委、教育局）、财政厅（局）：\n高校毕业生等青年就业关系民生福祉、社会稳定和高质量发展。各地要以习近平新时代中国特色社会主义思想为指导，落实党的二十大精神，强化就业优先导向，把促进青年特别是高校毕业生就业工作摆在更加突出的位置，综合施策，多措并举，着力促进高校毕业生等青年就业创业，确保就业局势总体稳定。现就有关工作通知如下：\n一、整合优化吸纳就业补贴和扩岗补助政策。合并实施一次性吸纳就业补贴和一次性扩岗补助政策，对招用毕业年度及离校两年内未就业高校毕业生及16—24岁登记失业青年，签订劳动合同，并按规定为其足额缴纳3个月以上的失业、工伤、职工养老保险费的企业，可按每招用1人不超过1500元的标准发放一次性扩岗补助。所需资金从失业保险基金支出，上年度失业保险基金滚存结余备付期限不足1年的省份，从就业补助资金支出。政策执行至2025年12月31日。\n二、延续实施国有企业增人增资政策。激励国有企业发挥示范带动作用，对按照工资效益联动机制确定的工资总额难以满足扩大高校毕业生招聘需求的国有企业，经履行出资人职责机构或其他企业主管部门同意，统筹考虑企业招聘高校毕业生人数、自然减员情况和现有职工工资水平等因素，可给予一次性增人增资，核增部分据实计入工资总额并作为下一年度工资总额预算基数。政策执行至2025年12月31日。\n三、实施先进制造业青年就业行动。开展先进制造业职业体验活动，组织高校毕业生等青年参观企业园区、车间厂房，感受工作氛围，增强职业认知。指定人社服务专员归集适合高校毕业生等青年的就业岗位，依托就业信息资源库和招聘平台，加强数据比对，促进高效匹配，并打包办理支持企业吸纳就业和助力人才发展系列政策。建立先进制造业企业集群职称评审“绿色通道”，赋予相关企业高层次人才举荐权，推动具备条件的先进制造业企业试点开展高级职称自主评审。\n四、鼓励引导基层一线就业。实施“三支一扶”计划，统筹推动其他基层服务项目实施，鼓励有条件的地方结合实际适当扩大招募规模。结合实施乡村振兴战略，适应基层治理模式创新需要，挖掘医疗卫生、养老服务、社会工作、司法辅助、科研助理等基层就业机会。对到基层就业的高校毕业生，按规定落实学费补偿、国家助学贷款代偿、高定工资、提前转正定级等政策，畅通职业发展通道。\n五、支持自主创业和灵活就业。强化青年创业支持，构建创业信息发布、政策咨询、流程办理、孵化服务等全周期服务机制，推进创业服务集成办理。对符合条件的高校毕业生创业项目，按规定给予一次性创业补贴。落实灵活就业社保补贴政策，扩大新就业形态就业人员职业伤害保障试点，保障青年灵活就业合法权益。\n六、大规模组织招聘对接服务。组织公共就业服务进校园，开展政策宣传、校园招聘、指导培训等活动。人社厅局长要结对帮扶就业压力大的高校，定向送资源、送岗位、送服务。组织开展“10+N”公共就业服务活动，将高校毕业生等青年群体作为服务重点，普遍设立招聘专区。加密招聘频次，高校毕业生集中的地市每周至少举办一次专业性招聘、每月至少举办一次综合性招聘。强化数字赋能，推进线上线下一体服务，探索岗位发布、组织对接、面试洽谈等“一站式”在线服务，便利青年求职应聘。\n七、强化青年求职能力训练和学徒培训。要加强高校毕业生等青年职业指导和求职能力训练，组织青年求职能力实训营，注重理论与实践相结合，开展模拟面试、简历诊断、职业规划等互动教学，组织企业参观、行业调研、岗位锻炼等体验活动。组织青年和毕业年度学生参加新型学徒培训，提高技能水平，按规定对承担学徒培训任务的企业和学校给予学徒培训补贴。\n八、实施百万就业见习岗位募集计划。支持企业、政府投资项目、事业单位开展就业见习，更多开发科研类、技术类、管理类、社会服务类见习岗位。2024年起，每年募集不少于100万个就业见习岗位，按规定给予就业见习补贴。对见习期未满与见习人员签订劳动合同的，各地可给予剩余期限见习补贴，政策执行至2025年12月31日。\n九、实施就业困难青年专项帮扶行动。强化未就业高校毕业生实名帮扶，建立实名台账，普遍提供至少1次政策宣介、1次职业指导、3次岗位推荐及1次培训或见习机会。强化困难高校毕业生结对帮扶，加强与农业农村、残联部门信息共享，及时将脱贫家庭毕业生、残疾毕业生、长期失业青年、求职补贴发放对象纳入帮扶台账，制定专项计划，开展“一对一”结对帮扶，针对性提供高质量岗位信息。\n十、高效办成高校毕业生就业一件事。统筹就业与人才政策服务事项，公开办理流程，明确办理时限，加快办理进度，推进档案接收、补贴申领、社保缴纳、落户手续等政策服务“一件事打包办”。有条件的地区可给予高校毕业生等青年人才公寓等支持，为青年就业提供便利。指导各级公共就业人才服务机构普遍设立青年就业服务窗口，有条件的地区要依托零工市场（零工驿站）、家门口就业服务站等现有资源建设一批青年就业驿站，为高校毕业生等青年就业提供一站式服务。\n十一、加强就业权益维护。加强人力资源市场监管，依法查处虚假招聘、违规收费、“黑中介”等违法违规行为，规范人力资源市场秩序。加大就业权益知识普及，在招聘会现场、服务大厅和相关网站发布防范求职陷阱的专门提示、典型案例、维权警示和投诉渠道，增强高校毕业生等青年风险防范意识和权益保护意识。加强公共就业服务活动和各类校园招聘活动参与企业资质及岗位审核，避免不合理招聘信息。\n各地要提高思想认识，把促进高校毕业生等青年就业作为重大政治责任，作为为民办实事重要内容，细化实施方案，明确职责分工、时间进度和工作要求。要细化完善政策，结合实际优化调整本地促进青年就业政策，能出早出、能出尽出，推动惠企利民。要加强协同配合，人力资源社会保障部门要加强工作统筹协调，建立工作调度机制，强化人员保障，确保各项工作任务落地见效；教育部门要加强高校毕业生就业指导服务，配合相关部门落实落细各项促就业政策；财政部门要做好就业补助资金保障，支持高校毕业生等青年就业政策落实。要强化宣传引导，加强对本地促进青年就业创业政策、经验做法和典型的宣传，引导高校毕业生等青年从实际出发选择就业方向。  \n人力资源社会保障部\n教育部\n财政部\n2024年5月17日', '2026-04-26 01:42:36', '2026-04-26 02:11:02');
INSERT INTO `policy_data` VALUES (24, '国务院办公厅关于加强普通高等学校毕业生就业工作的通知', '毕业生、创业、大学生、高校毕业生、就业、基层就业、三支一扶、自主创业、灵活就业、招聘、补贴、贷款、培训、见习', '来源：中国政府网\n发布日期：2009年01月23日\n发文机关：国务院办公厅\n发文字号：国办发〔2009〕3号\n原文链接：https://www.gov.cn/zhengce/content/2009-01/23/content_5468.htm\n\n国务院办公厅关于加强普通高等学校\n毕业生就业工作的通知\n\n国办发〔2009〕3 号\n\n各省、自治区、直辖市人民政府，国务院各部委、各直属机构：\n\n 普通高等学校毕业生（以下简称高校毕业生）是我国宝贵的人力资源。当前，受国际金融危机影响，我国就业形势十分严峻，高校毕业生就业压力加大。各地区、各有关部门要把高校毕业生就业摆在当前就业工作的首位，采取切实有效措施，拓宽就业门路，鼓励高校毕业生到城乡基层、中西部地区和中小企业就业，鼓励自主创业，鼓励骨干企业和科研项目单位吸纳和稳定高校毕业生就业。为进一步加强高校毕业生就业工作，经国务院同意，现就有关问题通知如下：\n\n 一、鼓励和引导高校毕业生到城乡基层就业。鼓励高校毕业生积极参加社会主义新农村建设、城市社区建设和应征入伍。围绕基层面向群众的社会管理、公共服务、生产服务、生活服务、救助服务等领域，大力开发适合高校毕业生就业的基层社会管理和公共服务岗位，引导高校毕业生到基层就业。对到农村基层和城市社区从事社会管理和公共服务工作的高校毕业生，符合公益性岗位就业条件并在公益性岗位就业的，按照国家现行促进就业政策的规定，给予社会保险补贴和公益性岗位补贴，所需资金从就业专项资金列支；对到农村基层和城市社区其他社会管理和公共服务岗位就业的，给予薪酬或生活补贴，所需资金按现行渠道解决，同时按规定参加有关社会保险。对到中西部地区和艰苦边远地区县以下农村基层单位就业、并履行一定服务期限的高校毕业生，以及应征入伍服义务兵役的高校毕业生，按规定实施相应的学费和助学贷款代偿。对具有基层工作经历的高校毕业生，在研究生招录和事业单位选聘时实行优先，在地市级以上党政机关考录公务员时也要进一步扩大招考录用的比例。\n\n 继续实施和完善面向基层就业的专门项目，扩大项目范围。相关项目由各有关部门继续加强组织领导，省级人民政府负责做好各类基层就业项目之间的政策衔接。2009年，中央有关部门继续组织实施“选聘高校毕业生到村任职”、“三支一扶”（支教、支农、支医和扶贫）、“大学生志愿服务西部计划”、“农村义务教育阶段学校教师特设岗位计划”等项目，各地也要因地制宜开展地方项目，鼓励和引导更多的高校毕业生报名参加。鼓励高校毕业生在项目结束后留在当地就业，今后相对应的自然减员空岗全部聘用服务期满的高校毕业生。对参加项目的高校毕业生给予生活补贴，所需资金按现行资金渠道解决，同时按规定参加有关社会保险。各专门项目相关待遇政策的衔接办法，由人力资源社会保障部、财政部、教育部、中央组织部、共青团中央等有关部门另行研究制定。\n\n 二、鼓励高校毕业生到中小企业和非公有制企业就业。各类中小企业和非公有制企业是高校毕业生就业的主要渠道。要进一步清理影响高校毕业生就业的制度性障碍和限制，为他们提供档案管理、人事代理、社会保险办理和接续、职称评定以及权益保障等方面的服务，形成有利于高校毕业生到企业就业的社会环境。对企业招用非本地户籍的普通高校专科以上毕业生，各地城市应取消落户限制（直辖市按有关规定执行）。企业招用符合条件的高校毕业生，可按规定享受相关就业扶持政策。劳动密集型小企业招用登记失业高校毕业生等城镇登记失业人员达到规定比例的，可按规定享受最高为200万元的小额担保贷款扶持。\n\n 三、鼓励骨干企业和科研项目单位积极吸纳和稳定高校毕业生就业。鼓励国有大中型企业特别是创新型企业创造条件，更多地吸纳有技术专长的高校毕业生就业。充分发挥高新技术开发区、经济技术开发区和高科技企业集中吸纳高校毕业生就业的作用，加强人才培养使用和储备。各地在实施支持困难企业稳定员工队伍的工作中，要引导企业不裁员或少裁员，更多地保留高校毕业生技术骨干，对符合条件的困难企业可按规定在2009年内给予6个月以内的社会保险补贴或岗位补贴，由失业保险基金支付；困难企业开展在岗培训的，按规定给予资金补助。承担国家和地方重大科研项目的单位要积极聘用优秀高校毕业生参与研究，其劳务性费用和有关社会保险费补助按规定从项目经费中列支，具体办法由科技、教育、财政等部门研究制定。高校毕业生参与项目研究期间，其户口、档案可存放在项目单位所在地或入学前家庭所在地人才交流中心。聘用期满，根据工作需要可以续聘或到其他岗位就业，就业后工龄与参与项目研究期间的工作时间合并计算，社会保险缴费年限连续计算。\n\n 四、鼓励和支持高校毕业生自主创业。鼓励高校积极开展创业教育和实践活动。对高校毕业生从事个体经营符合条件的，免收行政事业性收费，落实鼓励残疾人就业、下岗失业人员再就业以及中小企业、高新技术企业发展等现行税收优惠政策和创业经营场所安排等扶持政策。在当地公共就业服务机构登记失业的自主创业高校毕业生，自筹资金不足的，可申请不超过5万元的小额担保贷款；对合伙经营和组织起来就业的，可按规定适当扩大贷款规模；从事当地政府规定微利项目的，可按规定享受贴息扶持。有创业意愿的高校毕业生参加创业培训的，按规定给予职业培训补贴。强化高校毕业生创业指导服务，提供政策咨询、项目开发、创业培训、创业孵化、小额贷款、开业指导、跟踪辅导的“一条龙”服务。各地要建设完善一批投资小、见效快的大学生创业园和创业孵化基地，并给予相关政策扶持。鼓励支持高校毕业生通过多种形式灵活就业，并保障其合法权益，符合规定的，可享受社会保险补贴政策。\n\n 五、强化高校毕业生就业服务和就业指导。充分发挥人力资源市场配置资源的作用，强化公共就业服务的功能。人力资源社会保障、教育等部门及高校要加强协作，采取网络招聘、专场招聘、供求洽谈会和用人单位进校园等多种方式，大力开展面向高校毕业生的就业服务系列活动，为应届高校毕业生提供更多、更快、更好的免费就业信息和各类就业服务。高校要强化对大学生的就业指导，开设就业指导课并作为必修课程，重点帮助毕业生了解就业政策，提高求职技巧，调整就业预期。加强高校就业指导服务机构建设，落实人员、场地和经费。加强人力资源市场管理，严厉打击违法违规行为，加强招聘活动安全保障，维护高校毕业生就业权益。\n\n 六、提升高校毕业生就业能力。大力组织以促进就业为目的的实习实践，确保高校毕业生在离校前都能参加实习实践活动。完善离校未就业高校毕业生见习制度，鼓励见习单位优先录用见习高校毕业生。见习期间由见习单位和地方政府提供基本生活补助。拓展一批社会责任感强、管理规范的用人单位作为高校毕业生实习见习基地。从2009年起，用3年时间组织100万未就业的高校毕业生参加见习。加强高等职业院校学生的技能培训，实施毕业证书和职业资格证书“双证书”制度，努力使相关专业符合条件的应届毕业生通过职业技能鉴定获得相应职业资格证书。人力资源社会保障部门根据高校毕业生需要，提供专场或其他形式的职业技能鉴定服务，教育部门及高校要给予积极配合。对符合就业困难人员条件的高校毕业生，按规定给予鉴定补贴。\n\n 七、强化对困难高校毕业生的就业援助。对困难家庭的高校毕业生，高校可根据实际情况给予适当的求职补贴。各级机关考录公务员、事业单位招聘工作人员时，免收困难家庭高校毕业生的报名费和体检费。对离校后未就业回到原籍的高校毕业生，各地公共就业服务机构要摸清底数，免费提供政策咨询、职业指导、职业介绍和人事档案托管等服务，并组织他们参加就业见习、职业技能培训等促进就业的活动。对登记失业的高校毕业生，各地要将他们纳入当地失业人员扶持政策体系。对就业困难的高校毕业生和零就业家庭的高校毕业生，实施一对一职业指导、向用人单位重点推荐、公益性岗位安置等帮扶措施，按规定落实社会保险补贴、公益性岗位补贴等就业援助政策。\n\n 八、加强领导，明确责任。各地要加强对高校毕业生就业工作的组织领导，将高校毕业生就业纳入当地就业总体规划，统筹安排，确定目标任务，实行目标责任制，加强工作考核和督查。各有关部门要切实发挥职能，落实工作责任。各级人力资源社会保障部门要牵头制定和实施高校毕业生就业政策，并做好高校毕业生离校后的就业指导和就业服务工作。教育部门要指导高校大力加强在校生的就业指导和服务工作，并继续深化高等教育改革。财政部门要根据高校毕业生就业形势和实际需要，统筹安排资金用于促进高校毕业生就业。其他有关部门要认真履行职责，加强协调配合，共同推动工作。要大力开展高校毕业生就业工作的宣传，引导高校毕业生树立正确的就业观和成才观，形成全社会共同促进高校毕业生多渠道就业的良好舆论环境。各地要按照本通知要求，结合本地实际，制定切实有效的政策措施，创造性地开展工作，千方百计促进高校毕业生就业。\n\n \n\n 国务院办公厅\n\n二○○九年一月十九日', '2026-04-26 01:42:36', '2026-04-26 02:11:02');
INSERT INTO `policy_data` VALUES (25, '国务院办公厅关于做好2014年全国普通高等学校毕业生就业创业工作的通知', '毕业生、创业、大学生、高校毕业生、就业、基层就业、三支一扶、自主创业、灵活就业、招聘、补贴、贷款、培训、见习', '来源：中国政府网\n发布日期：2014年05月13日\n发文机关：国务院办公厅\n发文字号：国办发〔2014〕22号\n原文链接：https://www.gov.cn/zhengce/zhengceku/2014-05/13/content_8802.htm\n\n国务院办公厅关于做好2014年全国普通\n\n高等学校毕业生就业创业工作的通知\n\n国办发〔2014〕22号\n\n各省、自治区、直辖市人民政府，国务院各部委、各直属机构：\n\n 为进一步做好2014年全国普通高等学校毕业生（以下简称高校毕业生）就业创业工作，经国务院同意，现就有关问题通知如下：\n\n 一、高度重视高校毕业生就业创业工作\n\n 高校毕业生是国家宝贵的人才资源。做好高校毕业生就业创业工作，对于保持就业形势稳定，促进经济社会健康发展具有重要意义。近年来，各地区、各有关部门认真贯彻落实党中央、国务院的决策部署，高校毕业生就业创业工作取得积极进展。2014年，全国高校毕业生数量继续增加，就业工作任务十分艰巨。对此，党中央、国务院高度重视。党的十八届三中全会、中央经济工作会议对做好当前和今后一段时期高校毕业生就业创业工作提出明确要求，国务院对做好今年高校毕业生就业创业工作作出新的部署。各地区、各部门要切实将思想和行动统一到党中央、国务院的决策部署上来，充分认识做好高校毕业生就业创业工作的重要性和紧迫性，聚焦重点难点，继续把高校毕业生就业创业摆在就业工作的首要位置和整个经济社会发展的重要位置。要多方位拓宽就业渠道，结合产业转型升级开发更多适合高校毕业生的就业岗位，尤其要加快发展就业吸纳能力强的服务业，着力发展研发设计、现代物流、融资租赁、检验检测等对高校毕业生需求比较集中的生产性服务业，同时加快发展各类生活性服务业，拓展新领域，发展新业态，不断提高服务业从业人员比重。要充分发挥市场配置人力资源的决定性作用，着力改革创新，完善政策措施，强化就业创业服务，改善就业创业环境，引导高校毕业生转变就业观念，力争实现高校毕业生就业和创业比例都有所提高，确保高校毕业生就业形势稳定。\n\n 二、鼓励高校毕业生到城乡基层就业\n\n 各地区要结合城镇化进程和公共服务均等化要求，充分挖掘教育、劳动就业、社会保障、医疗卫生、住房保障、社会工作、文化体育及残疾人服务、农技推广等基层公共管理和服务领域的就业潜力，吸纳高校毕业生就业。要结合推进农业科技创新、健全农业社会化服务体系等，引导更多高校毕业生投身现代农业。全面落实高校毕业生到中西部地区和艰苦边远地区县以下基层单位就业的学费补偿和助学贷款代偿政策，尚未制定学费补偿和助学贷款代偿办法的地区，要在年内出台。高校毕业生在中西部地区和艰苦边远地区县以下基层单位从事专业技术工作，申报相应职称时，可不参加职称外语考试或放宽外语成绩要求。充分挖掘社会组织吸纳高校毕业生就业潜力，对到省会及省会以下城市的社会团体、基金会、民办非企业单位就业的高校毕业生，所在地的公共就业人才服务机构要协助办理落户手续，在专业技术职称评定方面享受与国有企事业单位同类人员同等待遇。继续统筹实施好大学生村官、“三支一扶”等各类基层服务项目，健全鼓励高校毕业生到基层工作的服务保障机制。各地要为高校毕业生参加实习、见习、志愿服务等活动创造条件，并将参加实习、见习、志愿服务等活动作为高校毕业生求职的实践经历。要加大工作力度，健全体制机制，鼓励支持更多高校毕业生参军入伍。\n\n 三、鼓励小型微型企业吸纳高校毕业生就业\n\n 各地区、各有关部门要认真落实《国务院关于进一步支持小型微型企业健康发展的意见》（国发〔2012〕14号），为小型微型企业发展创造良好环境，推动小型微型企业在转型升级过程中创造更多岗位吸纳高校毕业生就业。对小型微型企业新招用毕业年度高校毕业生，签订1年以上劳动合同并按时足额缴纳社会保险费的，给予1年的社会保险补贴，政策执行期限截至2015年年底。科技型小型微型企业招收毕业年度高校毕业生达到一定比例的，可申请最高不超过200万元的小额担保贷款，并享受财政贴息。对小型微型企业新招用高校毕业生按规定开展岗前培训的，各地要根据当地物价水平，适当提高培训费补贴标准。\n\n 四、实施大学生创业引领计划\n\n 2014年至2017年，在全国范围内实施大学生创业引领计划。通过提供创业服务，落实创业扶持政策，提升创业能力，帮助和扶持更多高校毕业生自主创业，逐步提高高校毕业生创业比例。各地要采取措施，确保符合条件的高校毕业生都能得到创业指导、创业培训、工商登记、融资服务、税收优惠、场地扶持等各项服务和政策优惠。各高校要广泛开展创新创业教育，将创业教育课程纳入学分管理，有关部门要研发适合高校毕业生特点的创业培训课程，根据需求开展创业培训，提升高校毕业生创业意识和创业能力。各地公共就业人才服务机构要为自主创业的高校毕业生做好人事代理、档案保管、社会保险办理和接续、职称评定、权益保障等服务。\n\n 各地区、各有关部门要进一步落实和完善工商登记、场地支持、税费减免等各项创业扶持政策。拓宽高校毕业生创办企业出资方式，简化工商注册登记手续。鼓励各地充分利用现有资源建设大学生创业园、创业孵化基地和小企业创业基地，为高校毕业生提供创业经营场所支持。对高校毕业生创办的小型微型企业，按规定落实好减半征收企业所得税、月销售额不超过2万元的暂免征收增值税和营业税等税收优惠政策。对从事个体经营的高校毕业生和毕业年度内的高校毕业生，按规定享受相关税收优惠政策。留学回国的高校毕业生自主创业，符合条件的，可享受现行高校毕业生创业扶持政策。\n\n 各银行业金融机构要积极探索和创新符合高校毕业生创业实际需求特点的金融产品和服务方式，本着风险可控和方便高校毕业生享受政策的原则，降低贷款门槛，优化贷款审批流程，提升贷款审批效率。要通过进一步完善抵押、质押、联保、保证和信用贷款等多种方式，多途径为高校毕业生解决反担保难问题，切实落实银行贷款和财政贴息。在电子商务网络平台开办“网店”的高校毕业生，可享受小额担保贷款和贴息政策。充分发挥中小企业发展专项资金的积极作用，推动改善创业环境。鼓励企业、行业协会、群团组织、天使投资人等以多种方式向自主创业大学生提供资金支持，设立重点面向扶持高校毕业生创业的天使投资和创业投资基金。对支持创业早期企业的投资，符合条件的，可享受创业投资企业相关企业所得税优惠政策。\n\n 五、深入实施离校未就业高校毕业生就业促进计划\n\n 各地区要将离校未就业高校毕业生全部纳入公共就业人才服务范围，采取有效措施，力争使每一名有就业意愿的未就业高校毕业生在毕业半年内都能实现就业或参加到就业准备活动中。各有关部门、各高校要密切协作，做好未就业高校毕业生离校前后信息衔接和服务接续，切实保证服务不断线。教育部门要将有就业意愿的离校未就业高校毕业生的实名信息及时提供给人力资源社会保障部门。人力资源社会保障部门要建立离校未就业高校毕业生实名信息数据库，全面实行实名制就业服务。各级公共就业人才服务机构和基层就业服务平台要及时主动与实名登记的未就业高校毕业生联系，摸清就业需求，提供有针对性的就业服务。教育部门和高校要加强对离校未就业高校毕业生的跟踪服务，为有就业意愿的高校毕业生持续提供岗位信息和求职指导。\n\n 各地区要结合本地产业发展需要和高校毕业生就业见习意愿及需求，扩大就业见习规模，提升就业见习质量，确保凡有见习需求的高校毕业生都能得到见习机会。根据当地物价水平，适当提高见习人员见习期间基本生活补助标准。高校毕业生见习期间参加职业培训的，按现行政策享受职业培训补贴。\n\n 各地区要继续推动离校未就业高校毕业生技能就业专项行动，结合当地产业发展和高校毕业生需求，创新职业培训课程，提高职业培训的针对性和实效性。在高校毕业生集中的城市，要提升改造一批适应高校毕业生特点的职业技能公共实训基地。国家级重点技工院校和培训实力雄厚的职业培训机构，要选择一批适合高校毕业生的培训项目，及时向社会公布。\n\n 六、加强就业指导、就业服务和就业援助\n\n 各地区、各有关部门、各高校要根据高校毕业生特点和求职需求，创新服务方式，改进服务措施，提高服务质量，促进更多的高校毕业生通过市场实现就业。加强网络信息服务，建立健全全国公共就业信息服务平台，加快招聘信息全国联网，更多开展网络招聘，为用人单位招聘和高校毕业生求职提供高效便捷的就业信息服务。积极开展公共就业人才服务进校园活动，为高校毕业生送政策、送指导、送信息，特别是要让高校毕业生知晓获取就业政策和岗位信息的渠道。精心组织民营企业招聘周、高校毕业生就业服务月、就业服务周、部分大中城市联合招聘高校毕业生专场活动和每季度的全国高校毕业生网络招聘月等专项服务活动，搭建供需信息平台，积极促进对接。高校要加强就业指导课程和学科建设，积极聘请专家学者、企业人力资源经理、优秀校友担任就业导师。\n\n 各地区、各高校要将零就业家庭、优抚对象家庭、农村贫困户、城乡低保家庭以及残疾等就业困难的高校毕业生列为重点对象实施重点帮扶。享受城乡居民最低生活保障家庭的毕业年度内高校毕业生的求职补贴要在离校前全部发放到位，求职补贴标准较低的要适当调高标准。各地可结合本地实际将残疾高校毕业生纳入享受求职补贴对象范围。党政机关、事业单位、国有企业要带头招录残疾高校毕业生。离校未就业高校毕业生实现灵活就业的，在公共就业人才服务机构办理实名登记并按规定缴纳社会保险费的，给予一定数额的社会保险补贴，补贴数额原则上不超过其实际缴费的2/3，最长不超过2年，所需资金从就业专项资金中列支。\n\n 七、进一步创造公平的就业环境\n\n 各地区、各有关部门要积极采取措施，促进就业公平。用人单位招聘不得设置民族、种族、性别、宗教信仰等歧视性条件，不得将院校作为限制性条件。省会及以下城市用人单位招聘应届毕业生不得将户籍作为限制性条件。国有企业招聘应届高校毕业生，除涉密等特殊岗位外，要实行公开招聘，招聘应届高校毕业生信息要在政府网站公开发布，报名时间不少于7天；对拟聘人员应进行公示，明确监督渠道，公示期不少于7天。各地区、各有关部门要严厉打击非法中介和虚假招聘，依法纠正性别、民族等就业歧视现象。加大对企业用工行为的监督检查力度，对企业招用高校毕业生不签订劳动合同、不按时足额缴纳社会保险费、不按时支付工资等违法行为，及时予以查处，切实维护高校毕业生的合法权益。\n\n 各地区、各有关部门要消除高校毕业生在不同地区、不同类型单位之间流动就业的制度性障碍。省会及以下城市要放开对吸收高校毕业生落户的限制，简化有关手续，应届毕业生凭《普通高等学校毕业证书》、《全国普通高等学校毕业生就业报到证》、与用人单位签订的《就业协议书》或劳动（聘用）合同办理落户手续；非应届毕业生凭与用人单位签订的劳动（聘用）合同和《普通高等学校毕业证书》办理落户手续。高校毕业生到小型微型企业就业、自主创业的，其档案可由当地市、县一级的公共就业人才服务机构免费保管。办理高校毕业生档案转递手续，转正定级表、调整改派手续不再作为接收审核档案的必备材料。\n\n 八、推动创新高校人才培养机制\n\n 深化教育改革，积极调整教育结构，加快发展现代职业教育，深化校企合作、工学结合，培养生产、建设、服务、管理一线的应用型和技能型人才。高校要明确办学定位，突出办学特色，加强就业教育，提高人才培养质量。各高校自2014年起要发布高校毕业生就业质量年度报告，完善就业与招生计划、人才培养、经费拨款、院校设置的联动机制，充分听取行业主管部门、经济部门、就业部门以及有关行业组织的意见，促进人才培养更好地适应经济社会发展需要。有关部门要开展产业升级人才需求预测研究，健全岗位需求统计调查制度，适时向社会发布行业人才需求信息，引导高校优化学科专业结构，探索制定行业岗位标准，促进高校依据市场需求完善专业培养课程。\n\n 九、加大宣传工作力度\n\n 各地区、各有关部门、各高校要高度重视宣传工作。要大力宣传党和政府对高校毕业生就业创业工作的重视和采取的政策措施，大力宣传高校毕业生到基层和中小微企业就业创业的先进事迹和典型经验，以正确的舆论导向引导社会各方面全面客观地看待当前就业形势，共同关心高校毕业生就业创业工作。教育部门和高校要将就业创业政策宣传到每一名高校毕业生，引导高校毕业生转变就业观念，以积极向上的心态走向社会，先就业、再择业，在平凡的岗位上创造不平凡的业绩。人力资源社会保障部门要深入用人单位进行政策宣传，引导用人单位履行社会责任，挖掘就业岗位吸纳更多高校毕业生就业。要在充分利用报纸、广播、电视等传统媒体的基础上，积极探索使用微博、微信、手机客户端等新媒体，深入解读促进高校毕业生就业创业的各项优惠政策。同时，密切关注舆情动态，及时了解和回应社会关切，掌握舆论主导权。\n\n 十、加强对高校毕业生就业创业工作的组织领导\n\n 各地要将高校毕业生就业工作列入政府政绩考核内容，进一步健全政府促进就业责任制度，在制定经济社会发展规划、调整产业结构和产业布局时，把高校毕业生就业作为重要目标予以考虑。要切实加大就业专项资金的投入力度，确保各项促进高校毕业生就业创业政策落到实处。就业工作联席会议成员单位要切实履行职责，加强协作配合，共同做好高校毕业生就业创业工作。各地区、各有关部门要按照本通知精神，制定具体措施，切实抓好贯彻落实。\n\n 国务院办公厅\n\n 2014年5月9日\n\n （此件公开发布）', '2026-04-26 01:42:36', '2026-04-26 02:11:02');
INSERT INTO `policy_data` VALUES (26, '国务院关于进一步做好普通高等学校毕业生就业工作的通知', '毕业生、创业、大学生、高校毕业生、就业、基层就业、三支一扶、自主创业、灵活就业、招聘、补贴、贷款、培训、见习', '来源：中国政府网\n发布日期：2011年06月01日\n发文机关：国务院\n发文字号：国发〔2011〕16号\n原文链接：https://www.gov.cn/zhengce/content/2011-06/01/content_6594.htm\n\n国务院关于进一步做好普通高等学校\n\n毕业生就业工作的通知\n\n国发〔2011〕16号\n\n各省、自治区、直辖市人民政府，国务院各部委、各直属机构：\n\n 普通高等学校毕业生（以下简称高校毕业生）是国家宝贵的人才资源，是现代化建设的重要生力军。做好高校毕业生就业工作，是促进经济发展和社会和谐的重要举措。近年来，各地区、各有关部门认真贯彻落实党中央、国务院的决策部署，做了大量工作，取得明显成效，高校毕业生就业形势总体保持稳定。预计“十二五”时期，高校毕业生数量仍将持续增长，促进高校毕业生就业任务依然十分繁重。各地区、各有关部门要继续把高校毕业生就业摆在就业工作的首位，进一步加大工作力度，多渠道开发就业岗位，完善相关政策措施，切实加强就业服务，千方百计促进高校毕业生就业。为进一步做好高校毕业生就业工作，现就有关问题通知如下：\n\n 一、适应加快转变经济发展方式和调整经济结构的进程，积极拓展高校毕业生就业领域\n\n （一）在构建现代产业体系中努力创造更多适合高校毕业生的就业机会。在推进战略性新兴产业发展中培育新的就业增长点，着力发展既具有较高科技含量又具有较强吸纳就业能力的智力密集型、技术密集型产业，开发更多适合高校毕业生的就业岗位。在加快转变经济发展方式和调整经济结构中实施有利于发挥劳动力比较优势的技术进步和产业升级技术战略，带动生产性就业岗位增长，努力扩大吸纳高校毕业生就业规模。大力发展具有增长潜力的生产性服务业和生活性服务业，积极鼓励发展服务外包、动漫、现代信息技术、现代服务业等产业，创造更多高校毕业生就业机会。积极支持和鼓励高校毕业生投身现代农业建设，鼓励农业企业吸纳高校毕业生就业。在安排政府投资、重大建设项目和制定产业规划时要充分考虑扩大就业的需要，探索建立投资带动就业评估机制，更好地发挥投资对就业的带动作用。及时发布和宣传行业发展规划和相关专业领域的人才规划，引导高校根据行业人才需求，有针对性地开展人才培养。各高校要根据经济社会发展和产业结构调整的需要，认真做好相关专业人才需求预测，合理调整专业设置，推进人才培养模式改革，强化实践教学和实习实训，提高人才培养质量。支持相关行业和产业与高校联合开展人才培养和岗位对接活动，使广大高校毕业生能够学有所用。\n\n （二）鼓励中小企业吸纳高校毕业生就业。中小企业是吸纳高校毕业生就业的主要渠道。要进一步改善中小企业发展环境，大力发展劳动密集型产业、服务业、小型微型企业和创新型科技企业，将落实中小企业扶持政策与做好高校毕业生就业工作结合起来，鼓励企业积极吸纳高校毕业生就业。对招收高校毕业生达到一定数量的中小企业，地方财政应优先考虑安排扶持中小企业发展资金，并优先提供技术改造贷款贴息。对劳动密集型小企业当年新招收登记失业高校毕业生达到一定比例的，可按规定申请最高不超过200万元的小额担保贷款，并享受财政贴息。对企业招收就业困难高校毕业生、签订劳动合同并缴纳社会保险费的，按规定给予社会保险补贴。高校毕业生到中小企业就业的，在专业技术职称评定、科研项目经费申请、科研成果或荣誉称号申报等方面，享受与国有企事业单位同类人员同等待遇。\n\n 二、鼓励引导高校毕业生面向城乡基层、中西部地区以及民族地区、贫困地区和艰苦边远地区就业\n\n （三）鼓励高校毕业生面向城乡基层就业。各地要根据统筹城乡经济和加快基本公共服务发展的需要，大力开发社会管理和公共教育、医疗卫生、文化等领域服务岗位，增加高校毕业生就业机会。要进一步完善相关政策，重点解决好他们在工资待遇、社会保障、人员编制、户口档案、职称评定、教育培训、人员流动、资金支持等方面面临的实际问题，鼓励和引导高校毕业生到城乡基层特别是城市社区和农村教育、医疗卫生、文化、科技等基层岗位工作。对在公益性岗位就业并符合条件的高校毕业生，按规定给予社会保险补贴和公益性岗位补贴。自2012年起，省级以上机关录用公务员，除部分特殊职位外，均应从具有2年以上基层工作经历的人员中录用。市（地）级以下机关特别是县乡机关招录公务员，应采取有效措施积极吸引优秀应届高校毕业生报考，录用计划应主要用于招收应届高校毕业生。要按照统一征集岗位、统一发布公告、统一组织考试、统一服务管理的原则，统筹实施“选聘高校毕业生到村任职”、“三支一扶”（支教、支农、支医和扶贫）、“大学生志愿服务西部计划”、“农村义务教育阶段学校教师特设岗位计划”等基层服务项目，做好各类项目之间的政策衔接，进一步落实对服务期满考核合格人员的就业政策措施。切实做好免费师范毕业生就业工作。积极做好征集高校毕业生入伍服义务兵役工作。\n\n （四）鼓励高校毕业生到中西部地区、民族地区、贫困地区和艰苦边远地区就业。要结合中部地区崛起和西部大开发战略的实施以及产业梯度转移的需要，鼓励和引导高校毕业生到中西部地区就业。各地要尽快出台并完善相关政策，对到中西部地区和艰苦边远地区县以下基层单位就业，服务期达到3年以上（含3年）的高校毕业生，按规定实施相应的学费和助学贷款代偿。对到艰苦边远地区或国家扶贫开发工作重点县就业的高校毕业生，在机关工作的，试用期工资可直接按试用期满后工资确定，试用期满后级别工资高定1至2档；在事业单位工作的，可提前转正定级，转正定级时薪级工资高定1至2级。\n\n 三、鼓励支持高校毕业生自主创业，稳定灵活就业\n\n （五）落实和完善创业扶持政策。各地区、各有关部门要进一步落实和完善各项创业扶持政策，改善创业环境，积极引导高校毕业生创业。持《就业失业登记证》（注明“自主创业税收政策”或附着《高校毕业生自主创业证》）的高校毕业生在毕业年度内（指毕业所在自然年，即1月1日至12月31日）从事个体经营的，3年内按每户每年8000元为限额依次扣减其当年实际应缴纳的营业税、城市维护建设税、教育费附加和个人所得税。2011年1月1日至2011年12月31日，对高校毕业生创办的年应纳税所得额低于3万元（含3万元）的小型微利企业，其所得减按50%计入应纳税所得额，按20%的税率缴纳企业所得税。发挥小额担保贷款政策促进就业的积极作用，对符合条件的高校毕业生自主创业的，可在创业地按规定申请小额担保贷款；从事微利项目的，可享受不超过10万元贷款额度的财政贴息扶持。对合伙经营和组织起来就业的，可根据实际需要适当提高贷款额度。要进一步改进和完善“小额担保贷款+信用社区建设+创业培训”联动工作机制。有条件的地区要加大财政投入，并积极引入风险投资资金，探索财政资金、风险投资等与大学生创业赛事的对接模式，规范发展民间融资，多渠道加大创业资金投入。要进一步完善和落实行政事业性收费减免等优惠政策，按照法律法规的规定，适当放宽市场准入条件，鼓励高校毕业生创业。\n\n （六）加强创业教育、创业培训和创业服务。各高校要广泛开展创业教育，积极开发创新创业类课程，完善创业教育课程体系，将创业教育课程纳入学分管理。积极推广成熟的创业培训模式，鼓励高校毕业生参加创业培训和实训，提高创业能力。对高校毕业生在毕业年度内参加创业培训的，根据其获得创业培训合格证书或就业、创业情况，按规定给予培训补贴。要根据高校毕业生特点和需求，组织开展政策咨询、信息服务、项目开发、风险评估、开业指导、融资服务、跟踪扶持等“一条龙”创业服务。在充分发挥各类创业孵化基地作用的基础上，因地制宜建设一批大学生创业孵化基地，并给予相关政策扶持。对基地内大学生创业企业要提供培训和指导服务，落实扶持政策，努力提高创业成功率，延长企业存活期。\n\n （七）稳定灵活就业。各地要鼓励支持高校毕业生通过多种形式灵活就业，并给予相关政策扶持。对符合就业困难人员条件的灵活就业高校毕业生，要按规定落实社会保险补贴政策。对申报灵活就业的高校毕业生，各级公共就业人才服务机构按规定提供人事、劳动保障代理服务，做好社会保险关系接续工作。\n\n 四、支持高校毕业生参加就业见习和技能培训，鼓励科研项目单位吸纳高校毕业生就业\n\n （八）支持高校毕业生参加就业见习。各地要结合当地产业发展需要和高校毕业生情况，鼓励和扶持一批规模较大并有一定社会影响力的企事业单位作为就业见习单位，为有见习需求的未就业高校毕业生提供见习机会。积极引导有条件的科技企业孵化器创建大学生科技创业见习基地。要进一步完善就业见习管理办法，明确见习对象范围、见习基地条件、见习补贴标准、见习考核评估等事项，进一步规范见习活动。认真落实见习期间基本生活补助政策，基本生活补助费用由见习单位和地方政府分担。各地要根据当地经济发展和物价水平，合理确定和及时调整基本生活补助标准。见习单位应加强见习场所的安全管理，并为参加见习的高校毕业生购买人身意外伤害保险。见习单位支出的见习补贴相关费用，不计入社会保险缴费基数，但符合税收法律法规规定的，可以在计算企业所得税应纳税所得额时扣除。\n\n （九）支持高校毕业生参加职业技能培训和技能鉴定。各地要积极组织有培训需求的高校毕业生参加职业技能培训和技能鉴定，帮助其提高就业能力。对高校毕业生在毕业年度内参加职业技能培训的，根据其取得职业资格证书（未颁布国家职业技能标准的职业应取得专项职业能力证书或培训合格证书）或就业情况，按规定给予培训补贴。对高校毕业生在毕业年度内通过初次职业技能鉴定并取得职业资格证书或专项职业能力证书的，按规定给予一次性职业技能鉴定补贴。对企业新招收毕业年度高校毕业生，在6个月之内开展岗前培训的，按规定给予企业职业培训补贴。\n\n （十）鼓励科研项目单位吸纳高校毕业生就业。鼓励高校、科研机构和企业，结合国家产业发展和技术进步的需要开展研究，并按照公开、自愿、双向选择的原则，在所承担的项目实施过程中，聘用优秀高校毕业生作为研究助理或辅助人员参与研究工作。在承担的民口科技重大专项、“973”计划、“863”计划、科技支撑计划以及国家自然科学基金等重大重点项目实施过程中，聘用高校毕业生的劳务性费用和有关社会保险费补助可按规定从项目经费中列支。聘用期满，根据工作需要可以续聘或到其他岗位就业，就业后工龄与参与研究期间的工作时间合并计算，社会保险缴费年限合并计算。\n\n 五、大力加强就业指导、就业服务和就业援助\n\n （十一）加强就业指导和就业服务。各高校要全面开展职业发展指导和就业创业教育，将就业指导课程纳入教学计划，建立贯穿于整个大学教育期间的职业发展和就业指导课程体系，帮助大学生树立正确的成才和就业观念。各地区、各有关部门要根据高校毕业生求职就业特点，创新就业服务模式，完善服务措施，采取组织企业进校园、召开专场招聘会和供求洽谈会、开展网络招聘等活动，为高校毕业生提供方便、快捷、直接、有效的就业信息服务。各地公共就业人才服务机构、高校毕业生就业指导服务机构及其他就业服务机构要加强合作，建立健全高校毕业生就业信息服务平台，提供政策发布、岗位信息、网络招聘、远程面试、指导咨询等就业服务。要大力推动互联网就业服务的健康发展，加强信息监督管理，规范互联网求职就业行为。要加强人力资源市场需求预测，完善职业供求信息收集和发布制度，引导高校毕业生理性求职、用人单位积极招聘和高校科学合理设置专业。鼓励各类职业中介机构为高校毕业生提供就业服务，对为登记失业高校毕业生提供服务并符合条件的给予职业介绍补贴。鼓励企业与高校合作，为大学生提供有针对性的指导和服务，帮助大学生提升专业能力和职业能力。全面落实为登记失业高校毕业生免费提供政策咨询、职业指导、职业介绍和人事档案托管等服务政策。支持工会、共青团、妇联等组织开展多种形式的高校毕业生就业创业扶持活动。\n\n （十二）开展就业失业登记。各级公共就业人才服务机构要按照就业促进法的规定，为已就业高校毕业生免费办理就业登记，并按规定提供人事、劳动保障代理服务。要进一步完善就业登记办法，建立就业登记与劳动合同管理、社会保险费缴纳联动机制，维护劳动者就业权益。对未就业的高校毕业生可按规定办理失业登记，并纳入户籍所在地失业人员统一管理，落实相关就业扶持政策。各级人力资源社会保障部门、教育部门和各高校要加强合作，进一步完善以实名制为基础的高校毕业生就业统计制度，做好高校毕业生毕业前后的信息衔接和服务接续。\n\n （十三）强化就业援助。各级公共就业人才服务机构要将就业困难的高校毕业生纳入当地就业援助体系，建立专门台账，实施“一对一”职业指导和重点帮扶，并向用人单位重点推荐，或通过公益性岗位安置就业。对符合条件的人员按规定落实社会保险补贴和公益性岗位补贴。各高校可根据困难家庭毕业生的实际情况，给予适当的求职补贴。各地要高度重视大城市聚居地长时间失业高校毕业生以及女性、残疾人和少数民族等高校毕业生的就业问题，提供有针对性的就业服务和就业指导，鼓励有条件的地区制定实施专门的就业扶持政策。\n\n （十四）保障就业权益。各城市应取消高校毕业生落户限制，允许高校毕业生在就（创）业地办理落户手续（直辖市按有关规定执行）。各地要按照就业促进法、劳动合同法、公务员法等的要求，进一步深化高校毕业生就业制度改革，简化高校毕业生就业程序。对到各类用人单位就业的高校毕业生，其职称评定、工资待遇、社会保险办理、工龄确定等要严格按照国家有关规定执行。高校毕业生从企业、社会团体到机关事业单位就业的，其参加基本养老保险缴费年限合并计算为工龄。要加大对各类企业特别是中小企业在劳动用工、缴纳社会保险费等方面的劳动监察力度，切实维护高校毕业生的合法权益。要进一步加强人力资源市场管理，大力开展人力资源市场清理整顿工作，严厉打击非法职业中介和招聘过程中的各类欺诈行为。要认真执行残疾人就业条例的有关规定，保障残疾人高校毕业生的就业权益。要切实落实取消就业体检中乙肝检测项目的有关规定，防止各类就业歧视，维护高校毕业生公平就业权利。\n\n 各地区、各有关部门要按照本通知精神，进一步加强对高校毕业生就业工作的领导，强化目标责任，把高校毕业生就业工作情况列入政府政绩考核内容，切实抓好贯彻落实。要加大对就业政策措施和先进典型的宣传力度，引导高校毕业生转变就业观念，营造良好的就业环境。\n\n 国 务 院\n\n 二○一一年五月三十一日', '2026-04-26 01:42:36', '2026-04-26 02:11:02');
INSERT INTO `policy_data` VALUES (27, '教育部关于做好2019届全国普通高等学校毕业生就业创业工作的通知', '毕业生、创业、大学生、高校毕业生、就业、基层就业、三支一扶、自主创业、灵活就业、招聘、补贴、贷款、培训、见习', '来源：中国政府网\n发文机关：教育部\n发文字号：教学〔2018〕8号\n原文链接：https://www.gov.cn/zhengce/zhengceku/2018-12/31/content_5441621.htm\n\n教育部关于做好2019届全国普通高等学校\n\n毕业生就业创业工作的通知\n\n教学〔2018〕8号\n\n各省、自治区、直辖市教育厅（教委），有关省、自治区人力资源社会保障厅，部属各高等学校、部省合建各高等学校：\n\n促进高校毕业生就业创业，既是民生，也是国计，事关广大群众切身利益，事关社会和谐稳定，事关社会主义现代化建设，事关高等教育健康发展。为深入贯彻习近平新时代中国特色社会主义思想和党的十九大精神，全面贯彻落实全国教育大会精神，把“稳就业”放在更加突出的位置，努力实现高校毕业生更高质量和更充分就业，现就有关事项通知如下。\n\n一、拓宽就业领域，着力促进高校毕业生多渠道就业\n\n1.引导毕业生到基层就业。各地各高校要深入贯彻落实中央《关于进一步引导和鼓励高校毕业生到基层工作的意见》，落实基层就业学费补偿贷款代偿、考研加分等优惠政策。要继续配合相关部门组织实施好“特岗计划”“大学生村官”“三支一扶”“大学生志愿服务西部计划”等基层就业项目，结合地方实际适当扩大地方基层项目的实施规模。要围绕乡村振兴战略，引导毕业生到现代农业生产、经营等领域就业创业。要发挥服务业最大就业容纳器的重要作用，鼓励毕业生到文化创意、健康养老、服务外包等现代服务业就业创业。鼓励高校毕业生到社会组织就业。\n\n2.促进毕业生到中小微企业就业。各地各高校要鼓励和促进高校毕业生到实体经济就业，充分发挥中小微企业吸纳毕业生就业的主渠道作用。要积极配合有关部门落实小微企业吸纳毕业生的社保补贴、培训补贴、降税减费等优惠政策。要加强与中小微企业沟通联系，广泛收集中小微企业招聘信息，积极组织中小微企业进校园招聘，进一步办好全国中小企业网上百日招聘等活动。\n\n3.服务国家战略开拓就业岗位。各地各高校要主动对接国家经济社会发展的人才需要，围绕“一带一路”建设、雄安新区建设、长江经济带发展、粤港澳大湾区建设、海南自贸试验区建设等，引导毕业生到重点地区、重大工程、重大项目、重要领域就业。要落实区域协调发展战略，鼓励毕业生到中西部地区、东北地区和艰苦边远地区就业创业。要加大对“三区三州”等深度贫困地区的教育脱贫攻坚力度，结合实际制定激励政策，引导毕业生到贫困地区就业创业。\n\n4.拓展新兴业态就业空间。各地各高校要结合学科专业特色，主动对接以技术集成和商业模式创新为特点的新业态人才需求，充分利用平台经济、众包经济、共享经济、数字经济等新业态，支持鼓励毕业生实现多元化就业。配合有关部门落实相应的社会保障政策和灵活就业、自主创业扶持政策，引导毕业生主动适应新就业形态、新用工方式。\n\n5.继续做好大学生征兵工作。各地各高校要深入贯彻习近平总书记给南开大学新入伍大学生回信和勉励语精神，认真落实学费资助、复学升学、就业创业等优惠政策。要密切配合兵役机关，面向毕业生、在校生、新生开展有针对性的宣传，集中播放征兵公益宣传片，发放应征入伍宣传单。落实好预订兵工作机制，为大学生入伍开辟绿色通道，鼓励更多大学生参军入伍。\n\n6.支持大学生到国际组织实习任职。各地各高校要加大经费资助、教育教学、升学就业等政策支持力度。高校要结合学科专业特色，加大双语种或多语种复合型国际化专业人才培养力度。将国际组织基本情况、职业发展路径等内容，纳入大学生就业指导教材和课程。进一步完善信息服务平台，及时收集发布国际组织招聘信息，开展专家讲座、政策咨询、社团活动等系列指导服务。鼓励高校与国际组织开展合作交流，进一步拓展实习任职渠道。\n\n二、推动双创升级，着力促进高校毕业生自主创业\n\n7.全面深化高校创新创业教育改革。各地各高校要将创新创业教育贯穿人才培养全过程，把创新创业教育和实践课程纳入高校必修课体系，促进创新创业教育与专业教育有机结合、与思想政治教育深度融合。开展好大学生创新创业训练计划、中国“互联网+”大学生创新创业大赛和“青年红色筑梦之旅”活动，着力培养学生的创新意识、实践能力和奋斗精神。\n\n8.落实完善创新创业优惠政策。各地要配合有关部门深化商事制度改革，进一步完善落实税费减免、创业担保贷款、创业培训补贴等优惠政策。各高校要按照《普通高等学校学生管理规定》要求，进一步细化创新创业学分积累与转换、弹性学制管理、保留学籍休学创业、支持创新创业学生复学后转入相关专业学习等政策，允许本科生用创业成果申请学位论文答辩。\n\n9.加大创新创业场地和资金扶持力度。各地各高校要加强大学科技园、创业孵化基地等创新创业平台建设，为大学生创新创业提供场地支持。各高校要积极推动各类研究基地、实验室、仪器设备等教学资源向创新创业学生开放。有条件的地区要积极推进设立高校毕业生就业创业基金，高校要通过政府支持、学校自设、校外合作、风险投资等方式多渠道筹措资金，支持大学生自主创业。\n\n10.加强创业指导与服务。各地各高校要进一步建立健全各级各类大学生创业服务平台，为大学生创业提供项目对接、财税会计、法律政策、管理咨询等深度服务。鼓励各高校聘请行业专家、创业校友、企业家等担任大学生创业团队指导教师，鼓励专业教师、实验室老师全程指导大学生创新创业。\n\n三、强化服务保障，着力提高就业创业指导服务水平\n\n11.健全精准信息服务机制。加强部省校三级就业服务体系建设，建立毕业生求职和用人单位需求数据库，运用大数据技术实现供需智能匹配，为毕业生精准推送政策、岗位和指导。要进一步发挥校园招聘市场的主体作用，鼓励组织分层次、分类别、分行业的校园招聘活动，支持举办区域性、行业性联合招聘活动。高校举办的大型校园招聘活动要向其他高校有组织开放。做好在内地（祖国大陆）高校就读的港澳台毕业生就业服务工作。\n\n12.提升毕业生就业能力。各地各高校要加强高校学生职业生涯发展教育，对低年级学生着重进行职业生涯启蒙，对高年级学生着重提升职业素质和求职技能。要结合就业形势和毕业生特点，帮助毕业生调整就业预期，找准职业定位。要多方搭建社会实践、实习实训、职业体验等实践平台，增强学生专业技能和职业能力。鼓励学生在取得毕业证书的同时考取行业企业认可度高的多种类型的培训（或认证）证书。\n\n13.强化就业困难群体帮扶。各地各高校要准确掌握建档立卡贫困家庭、少数民族、身体残疾等毕业生情况，建立帮扶台账，做到分类帮扶、精准发力。高校要建立校院领导、专业教师、辅导员等全员参与的“一对一”精准帮扶机制。充分挖掘校友、行业企业等社会资源，优先为困难群体推荐岗位。各地要积极创造条件，争取专项资金，开展就业困难毕业生专项培训，提高其就业能力。要配合有关部门落实好求职创业补贴政策，做好离校未就业毕业生的信息衔接和服务接续工作。\n\n14.切实保护毕业生就业权益。各地各高校要加强校园内招聘活动管理，严禁发布性别、民族、院校、学习方式（全日制和非全日制）等歧视性信息，严格审核用人单位资质、工作岗位信息，重点审核就业中介机构和境外用人单位，严密防范招聘陷阱、就业欺诈、“培训贷”、传销等不法行为。普及就业创业有关法律法规知识，提高大学生的法律意识和维权意识。加强毕业生和用人单位诚信教育和管理，做到诚信签约、诚实履约。\n\n15.加快高校就业创业指导队伍建设。各地各高校要加快建设一支职业化、专业化、专家化的就业创业指导队伍，在专业技术职务评聘和绩效考核中充分考虑指导教师的工作性质和工作业绩，予以适当支持。要建立高校毕业生就业创业指导教师培训机制，开展专业培训，鼓励指导教师到行业企业挂职锻炼。要定期对辅导员、班主任等就业工作人员进行集中轮训，全面提高政策水平和工作能力。\n\n16.积极发挥高校毕业生就业状况反馈作用。各地各高校要进一步落实高校毕业生就业质量年度报告编制发布制度，着力完善统计指标和内容，按时向社会发布高校毕业生就业质量年度报告。加快形成就业与招生计划、人才培养联动机制。各地要根据经济社会发展需要以及本地区毕业生就业总体状况，主动对接地区、行业、产业需求，进一步建立完善高校学科专业、培养层次、培养类型动态调整机制，努力实现本地区高等教育规模和结构的科学配置和布局。\n\n四、加强组织领导，着力深化思想教育和宣传引导\n\n17.强化组织领导。各地各高校要认真落实就业工作“一把手”工程，切实做到“机构、场地、人员、经费”四到位。高校主要负责同志要亲自部署，分管领导要靠前指挥，院系领导要落实责任，辅导员（班主任）要密切关注毕业生就业进展情况。健全就业、招生、教学、学工、团委、科研等机构分工负责、协同推进的工作机制，千方百计促进毕业生就业创业。\n\n18.深化思想教育和宣传引导。各地各高校要组织大学生学习习近平总书记关于青年成长成才的重要论述，教育引导毕业生把个人理想融入国家和民族事业当中，鼓励毕业生到基层、西部、祖国最需要的地方建功立业。要广泛宣传解读国家和地方促进就业创业的政策措施，帮助毕业生知晓政策、用好政策，营造就业创业良好舆论氛围。\n\n19.进一步加强就业工作规范管理。各地各高校要建立就业统计工作责任制，健全毕业生参与的就业状况统计核查机制。各高校要认真落实统计工作“四不准”要求，即不准以任何方式强迫毕业生签订就业协议，不准将毕业证书、学位证书发放与签约挂钩，不准以户档托管为由劝说毕业生签订虚假协议，不准将顶岗实习、见习证明材料作为就业证明材料。各地要对高校毕业生就业工作及数据进行认真核查，对查实的弄虚作假等问题要严查严处，并进行通报。\n\n教育部 \n\n2018年11月27日', '2026-04-26 01:42:36', '2026-04-26 02:11:02');
INSERT INTO `policy_data` VALUES (28, '人力资源社会保障部办公厅 税务总局办公厅 市场监管总局办公厅关于推动个人创业“高效办成一件事” 的实施意见', '创业、就业、灵活就业、补贴', '来源：中国政府网\n发文机关：人力资源社会保障部办公厅 税务总局办公厅 市场监管总局办公厅\n发文字号：人社厅发〔2025〕25号\n原文链接：https://www.gov.cn/zhengce/zhengceku/202507/content_7033089.htm\n\n人力资源社会保障部办公厅 税务总局办公厅 市场监管总局办公厅关于推动个人创业“高效办成一件事” 的实施意见\n人社厅发〔2025〕25号\n各省、自治区、直辖市及新疆生产建设兵团人力资源社会保障厅（局）、税务局、市场监管局（厅、委）：\n为深入贯彻落实《国务院办公厅关于印发〈“高效办成一件事”2025年度第一批重点事项清单〉的通知》（国办函〔2025〕3号）要求，积极推动个人创业“一件事”高效办理，现提出以下实施意见。\n一、总体要求\n以习近平新时代中国特色社会主义思想为指导，全面贯彻落实党的二十大和二十届二中、三中全会精神，坚持以人民为中心的发展思想，坚持问题导向和目标导向相结合，把推动高效办理就业创业证申领、无雇工个体工商户及灵活就业人员参加养老保险登记、创业补贴申领、经营主体登记注册和纳税人信息确认“一件事”，作为支持个人创业、优化创业服务、提升创业质量的重要抓手，系统梳理本地劳动者创业相关政务服务事项，优化经办流程，强化政策、业务、系统协同和数据共享，强化跨部门联动工作机制，最大限度实现个人创业便利快捷。\n二、主要任务\n（一）规范“一次办”服务流程。从创业者视角出发，将个人创业相关的跨部门政务服务事项进行同步办理，实现“一次办”（办理流程参考图见附件）。人社部门要积极受理个人创业相关政务服务事项，通过数据共享方式获取市场监管部门经营主体登记注册信息，对应办理就业创业证申领、无雇工个体工商户及灵活就业人员参加养老保险登记，通过12333政务服务平台主动告知创业补贴政策内容和经办渠道。对达到创业补贴申领条件的，通过“直补快办”方式及时兑现。市场监管部门依托“一网通办”平台做好经营主体登记注册信息共享推送。税务部门接收经营主体登记注册信息后做好纳税人信息确认。\n（二）畅通“一网办”信息系统。对个人创业“一件事”涉及事项的经办系统和共享数据需求进行梳理摸底，形成可同步办理的事项目录，基于各地业务经办服务平台，提供智能办理服务，支持各后续部门同步完成提示提醒，实现各服务事项“信息共享、及时流转、如期反馈”，为创业者提供业务办理进度通知或查询服务。要加快线上服务平台建设和升级，打造更多“线上办”“掌中办”应用场景，努力提升服务便捷度。\n（三）完善“一站办”联动机制。在现有政务服务中心基础上，推动将个人创业“一件事”涉及事项纳入集中办理，联动各部门服务窗口，实现统一受理、一站联办。相关部门服务窗口在完成本部门服务事项业务经办同时，要主动提示创业者办理后续关联服务事项。有条件的地方，要在“一站”办理基础上实现“一柜”办理，加快推动“前台综合受理、后台分类审批、综合窗口出件”。\n（四）优化“一张表”申请材料。简化个人创业“一件事”服务事项涉及的各项表单材料，优化整合申请材料“一张表”的内容信息，推动部门间信息共享互认，实现“一次采集、多方通用”。对各服务事项按照“能简则简、应减尽减”原则，明确必需提交采集的材料和数据，对可以通过跨部门共享或核验方式获取的材料和数据等信息，创业者个人无需重复提交。\n（五）编制“一单清”服务指南。逐项明确个人创业“一件事”服务事项的设定依据、责任单位、服务内容、服务流程，形成个人创业“一件事”目录清单。各地可根据本地实际和创业者需求，增加纳入目录清单的服务事项。针对纳入目录清单的服务事项，编制个人创业“一件事”服务指南，细化受理条件、办理窗口、经办流程、办结时限、结果反馈等事项，为创业者提供“一单清”办事指引。\n三、工作要求\n（一）加强组织实施。各地要将“高效办成一件事”作为践行以人民为中心发展思想、推动政务服务提质增效、提升创业者获得感、促进高质量充分就业的重要抓手，提高工作重视程度，坚持规范性与便捷性相统一，切实将工作落细落实。\n（二）强化部门协同。人力资源社会保障部门要切实履行工作牵头职责，税务、市场监管等部门要分工协作，落实职责，强化工作合力。要通过召开专题会议、定期督导等方式，及时研究解决遇到的困难和问题，确保高质量完成各项工作。人力资源社会保障部将会同相关部门适时开展调度。\n（三）做好宣传引导。要采取多种形式做好个人创业“一件事”的政策宣传解读工作，提高公众知晓度，让创业者充分享受服务便利，进一步优化创业促进就业政策环境。\n附件：个人创业“一件事”办理流程参考图（略）\n人力资源社会保障部办公厅\n税务总局办公厅\n市场监管总局办公厅\n2025年6月23日', '2026-04-26 01:51:56', '2026-04-26 02:11:02');
INSERT INTO `policy_data` VALUES (29, '国务院就业促进和劳动保护工作领导小组关于印发《加力重点领域、重点行业、城乡基层和中小微企业岗位挖潜扩容 支持重点群体就业创业实施方案》的通知', '毕业生、创业、高校毕业生、就业、基层就业、三支一扶、自主创业、招聘、贷款、培训、见习', '来源：中国政府网\n发文机关：国务院就业促进和劳动保护工作领导小组\n发文字号：国就劳发〔2025〕2号\n原文链接：https://www.gov.cn/zhengce/zhengceku/202503/content_7015975.htm\n\n国务院就业促进和劳动保护工作领导小组\n关于印发《加力重点领域、重点行业、城乡基层和中小微企业岗位挖潜扩容 支持重点群体就业创业实施方案》的通知\n国就劳发〔2025〕2号\n国务院就业促进和劳动保护工作领导小组各成员单位，各省、自治区、直辖市及新疆生产建设兵团相关议事协调机构：\n为落实中央经济工作会议精神，按照国务院第51次常务会议要求，国务院就业促进和劳动保护工作领导小组办公室制定了《加力重点领域、重点行业、城乡基层和中小微企业岗位挖潜扩容 支持重点群体就业创业实施方案》，已经国务院就业促进和劳动保护工作领导小组第三次全体会议审议通过。现印发给你们，请认真贯彻执行。\n国务院就业促进和劳动保护工作领导小组\n2025年3月6日\n\n加力重点领域、重点行业、城乡基层和中小微企业岗位挖潜扩容\n支持重点群体就业创业实施方案\n就业是民生之本。为有效应对外部环境和国内经济运行变化对就业影响，促进高校毕业生、脱贫人口、农民工、退役军人等重点群体就业，现就加力重点领域、重点行业、城乡基层和中小微企业岗位挖潜扩容，支持重点群体就业创业有关事项提出以下实施方案：\n一、总体要求\n坚持以习近平新时代中国特色社会主义思想为指导，深入贯彻党中央、国务院促进高质量充分就业的决策部署，坚持目标导向、问题导向，坚持市场化社会化就业方向，强化就业优先，找准主攻方向，聚焦重点群体，着力加强政策支持、培训赋能、服务助力，全力稳存量、扩增量、提质量、防变量，加力构建就业友好型发展方式，努力促进高质量充分就业，确保就业局势基本稳定。\n二、推进实施岗位开发计划的重点方向\n（一）挖掘先进制造等新质生产力就业潜力。实施新一轮十大重点行业稳增长工作方案，研究保持制造业合理比重投入机制，落实“两重”、“两新”政策，稳住制造业就业规模。持续开展先进制造业促就业行动，实施制造业重点产业链高质量发展行动，培育智能装备、电子信息、生物医药、低空经济等就业新空间。加大科技和创新型中小企业、高新技术企业、专精特新中小企业、专精特新“小巨人”企业、制造业单项冠军企业、瞪羚企业、独角兽企业等培育力度，创造更多高质量岗位。实施“人工智能+”行动，增强新兴技术创造就业效应。\n（二）推动消费新热点转化为就业新渠道。健全绿色消费激励机制，发展新能源、循环利用、节能环保、节水减污等产业，扩大绿色低碳复合型人才需求。加快文旅与科技及相关产业融合，培育文化创意、电竞娱乐、冰雪经济、演艺、赛事等业态，结合落实过境免签政策支持开展国际旅游服务，扩大文旅就业机会。布局培育便民生活圈、商品集散中心、骨干农产品批发市场，打造“夜经济”等消费场景，发展数字消费，带动商贸领域就业。利用相关引导基金，促进服务外包高质量发展扩大就业。\n（三）放大重大工程项目建设就业增量。跟踪政府投资建设重点项目，大力实施城市更新，加大城市更新领域投资，加快释放带动就业效果。加大以工代赈实施力度，增加以工代赈中央预算内投资规模，吸纳更多低收入群众就地就近务工。深入挖掘交通、水利、农业农村、林草生态、灾后重建等领域重点工程项目用工潜力，在更大范围更广领域实施以工代赈方式，进一步扩大就业容量。\n（四）围绕保障重点民生服务促进就业。壮大养老服务产业，加快建立养老服务师职业资格等制度，拓宽银发经济岗位需求。聚焦群众防病就医需要，推进医疗卫生强基工程，加强护士队伍建设，吸纳各类卫生健康人才。增加普惠托育服务，支持社会力量参与多种模式托育服务，更多吸纳就业。促进家政服务业提质扩容，加快修订相关职业标准，加强品牌培育，实施巾帼家政数字化服务项目，扩大家政服务从业规模。加强康养托育领域人力资源服务，推动相关生活性服务业高质量发展。发展重度残疾人托养照护服务，推进精神障碍社区康复服务，加强康复、心理治疗等专业人才队伍建设。结合房地产开发竣工进度，及时扩大物业服务人员配备。\n（五）拓宽劳动者城乡基层服务空间。推进乡村全面振兴，培育壮大县域富民产业，更好带动农民参与产业发展、分享增值收益，创造更多家门口就业机会。加大社区专职工作人员岗位供给，继续实施高校毕业生基层服务项目，适当扩大“三支一扶”计划、“西部计划”招募规模。引导法学专业毕业生、律师职业实习人员等到西部基层提供法律援助服务。支持各地使用工会经费合理配备工会社会工作者。支持社会组织吸纳就业。\n（六）提高民营企业和中小微企业就业吸引力。建好用好全国中小企业服务“一张网”，持续开展“一起益企”中小企业服务行动，促进企业健康发展，更好发挥就业主渠道作用。办好中国国际中小企业博览会，助力开拓多样化全球市场。健全创业带动就业保障制度，进一步优化创业氛围，鼓励重点群体创办各类经营主体。\n（七）稳定机关事业单位和国有企业招聘规模。盘活各地教育类、卫生类等事业单位编制资源，加快招聘组织，强化示范引领作用。推动高校设立助学助管岗位或就业见习岗位，支持国家高新区内各类创新主体及承担国家科技计划的单位加大科研助理岗位开发力度。鼓励国有企业带头吸纳就业，稳定招聘规模。开展公益性岗位评估，更好适应新的需求，强化动态管理，发挥好兜底安置作用。\n三、加大重点群体就业创业支持\n（一）加大减负稳岗支持力度。健全涉企收费长效监管机制，严格规范执法行为，合理降低融资、物流等显性成本和市场准入、招投标等隐性成本。继续实施阶段性降低失业、工伤保险费率政策。鼓励金融机构创新稳岗扩岗专项贷款产品，适度提高贷款额度，加大对不裁员少裁员劳动密集型企业等促进稳定就业的企业金融支持力度。\n（二）鼓励企业更多吸纳就业。对用人单位新招用符合条件人员就业的，及时落实各项就业政策。研究将符合条件的社会组织纳入一次性扩岗补助政策范围。延续国有企业一次性增人增资政策实施期限至2026年底。统筹用好各类产业基金促进就业，支持企业加大人力资本投入，提高劳动者特别是低收入劳动者工资水平。\n（三）强化自主创业政策支持。推广高效办成个人创业“一件事”服务，引导劳动者结合产业发展、科技创新、社会服务等需求，分赛道多领域创新创业。借鉴支持开发区的政策举措，研究推出支持创新创业园区的政策，推动创新成果落地，及早转化为增长动能、就业潜能。用好各类创业孵化载体，鼓励政府投资的孵化器安排一定比例场地，放宽重点群体免费入驻门槛。鼓励有条件地方提高创业担保贷款额度，推动政府性融资担保体系加力支持就业创业。\n（四）推进就业服务提质增效。加强挖潜扩容重点领域重点行业用工服务保障力度，建立岗位归集发布制度，及时对接相关产业发展和重点投资，把岗位创造落实到具体的项目和企业。充分发挥公共就业服务机构、零工市场、市场化服务机构等作用，密集开展系列招聘服务活动，加强岗位需求和重点就业群体的数据比对，搭建供需对接平台。结合文化旅游、休闲消费、冰雪经济等季节性用工需求，组织区域性、专业性、针对性强的招聘活动。\n（五）开展大规模职业技能培训。支持行业主管部门聚焦岗位挖潜扩容的重点方向，分行业领域制定培训计划，加大培训资金投入、设施建设、企业参与等支持力度，研究支持企业建设技能实训设施，大力推行“岗位需求+技能培训+技能评价+就业服务”培训模式，提高培训层次，培养更多发展所需人才。指导相关领域行业企业实施“新八级工”制度，构建凸显技能价值导向的薪酬分配体系，提高相关领域行业技能劳动者获得感。\n（六）切实保障劳动者合法权益。指导企业依法合规用工，构建和谐劳动关系。合理调整最低工资标准，保障低收入劳动者劳动报酬权益。持续开展清理整顿人力资源市场秩序专项行动，依法查处就业歧视、黑职介、招聘欺诈等违法行为，规范劳务派遣用工，纠治“假外包、真派遣”等乱象。指导企业与职工通过协商稳定就业岗位，规范裁员行为。推动劳动就业领域矛盾风险多元化解，建立跨部门工作联动机制，切实防范化解规模性失业和群体性事件风险。\n四、切实抓好组织实施和工作保障\n（一）细化工作方案。各地区、各有关部门要高度重视，把落实重点领域、重点行业、城乡基层和中小微企业岗位挖潜扩容支持重点群体就业创业实施方案作为当前稳就业工作的重要抓手。各部门要按照方案要求，细化岗位开发计划的具体举措、工作目标和进度安排；各地区要结合本地实际，合理选择确定本地区挖潜扩容的重点方向，并细化具体目标和支持举措，确保可实施、可检验。各部门、各地区具体举措和方案请于3月25日前报领导小组办公室。\n（二）加强协同联动。进一步突出就业优先导向，在方案实施过程中要强化政策协同，将就业影响纳入宏观政策取向一致性评估范围，在重大项目、重大政策出台前开展就业影响评估，提升经济发展就业带动力。要强化岗位协同，建立部门间岗位挖潜扩容会商机制，推动岗位开发、技能提升、服务匹配同步开展，更好提升人岗匹配效率。\n（三）强化资金保障。各地要做好就业资金保障，统筹使用各类相关资金，确保各项政策落实。要完善资金监管机制，推动政策网上申领、网上审核、网上发放、直补个人，对违规使用、骗取套取资金的依法依规严惩。\n（四）抓好工作调度。依托国务院就业促进和劳动保护工作领导小组，建立常态化岗位挖潜扩容调度机制，各部门、各地区岗位开发和方案实施情况请于每季度结束后次月10日前提供至人力资源社会保障部，人力资源社会保障部要按季度开展工作调度，适时向领导小组报告。对工作进展慢、效果不明显的，及时督促提醒。\n（五）营造良好氛围。要加强政策宣传解读，大力宣传党中央、国务院决策部署，系统阐释党和政府关心重视就业的政策举措，提高知晓度和参与度。广泛挖掘选树一批积极吸纳就业的典型行业企业、着力挖潜扩容的部门和地方典型经验，加大宣传力度，发挥示范引领作用。要加强就业观念引导，大力弘扬“基层就业，同样出彩”，大力宣传劳动者就业创业典型事迹，以择业新观念打开就业新天地。', '2026-04-26 01:51:56', '2026-04-26 02:11:02');
INSERT INTO `policy_data` VALUES (30, '教育部关于做好2024届全国普通高校毕业生就业创业工作的通知', '毕业生、创业、大学生、高校毕业生、就业、基层就业、三支一扶、自主创业、灵活就业、招聘、补贴、培训', '来源：中国政府网\n发文机关：教育部\n发文字号：教就业〔2023〕4号\n原文链接：https://www.gov.cn/zhengce/zhengceku/202312/content_6918529.htm\n\n教育部关于做好2024届全国普通高校毕业生就业创业工作的通知\n教就业〔2023〕4号\n各省、自治区、直辖市教育厅（教委），新疆生产建设兵团教育局，有关省、自治区人力资源社会保障厅，部属各高等学校、部省合建各高等学校：\n高校毕业生是国家宝贵的人才资源。为深入学习贯彻习近平新时代中国特色社会主义思想和党的二十大精神，全面落实党中央、国务院对高校毕业生就业创业工作的决策部署，教育部决定实施“2024届全国普通高校毕业生就业创业促进行动”，进一步完善高校毕业生就业创业服务体系，全力促进高校毕业生高质量充分就业。现就有关事项通知如下。\n一、把高校毕业生就业工作摆在更加突出位置\n1.强化统筹部署。各地各高校要把高校毕业生就业作为重中之重、摆在更加突出的位置，纳入领导班子重要议事日程，健全就业促进机制。要按照“秋季校园招聘月”“寒假暖心行动”“春季攻坚行动”“百日冲刺行动”的部署，结合工作实际，统筹做好本地本校工作安排，落实落细各项工作要求，确保高校毕业生就业局势总体稳定。\n2.强化协同联动。各省级教育部门要主动加强与组织、人力资源社会保障、发展改革、财政等部门沟通衔接、分工合作、协同联动，把高校毕业生作为公共服务的重点群体，争取更多岗位、资金、培训、服务等公共资源向高校毕业生倾斜。要牵头成立高校毕业生就业工作专班，制定工作方案，明确任务清单，进一步优化工作机制，全力推进各项任务落实。\n3.强化高校责任。高校是做好本校毕业生就业工作的责任主体，主要负责同志是第一责任人，分管负责同志是直接责任人。加强学校党委组织领导，把就业工作列入学校党委常委会重要议题定期研究推进。建立健全“校—院（系）”两级就业工作领导小组，分别制定就业工作方案，分级落实工作责任。加强部门工作协同，完善激励考评机制，调动全校力量形成全员促就业工作合力。\n二、大力开拓市场化社会化就业渠道\n4.深入开展“访企拓岗”专项行动。各地各高校要持续深入开展“高校书记校长访企拓岗促就业专项行动”。高校书记、校（院）长和校领导班子成员要认真落实“两个100”要求，有针对性拓展就业市场；二级院系要结合学科专业特点，精准有效访企拓岗，足质足量开拓就业岗位，上一年度初次毕业去向落实率低于本校平均水平的二级院系，原则上院系领导班子成员和专业负责人平均每人联系走访用人单位不少于10家。要结合毕业生就业需求，提升岗位的利用率和访企拓岗的实效性。要通过访企拓岗深度了解行业企业的人才需求，深化人才培养改革，推动供需精准对接。鼓励各地结合产业发展需求和学校办学特色组织开展集中走访。\n5.推进实施“万企进校园”计划。各地各高校要充分发挥校园招聘主渠道作用，主动邀请用人单位进校开展招聘活动，提升每场校园招聘活动的实际效果。要结合毕业生求职就业意愿，大力拓展岗位资源，努力为毕业生提供优质的就业岗位信息。支持院系积极开展小而精、专而优的小型专场招聘活动。加强校园招聘活动组织管理，认真审核校园招聘信息，确保校园招聘活动安全、规范、有序开展。\n6.全面推广使用国家大学生就业服务平台。优化升级国家大学生就业服务平台功能，深入开展“24365携手促就业精准服务”，持续加强就业岗位的互联共享和精准推送。各省级和高校就业网在满足本地本校招聘需求的基础上，积极与平台共享更多岗位信息。各地各高校要组织就业工作人员、毕业班辅导员和有求职意愿的毕业生及时注册使用平台，确保就业政策、资讯、岗位信息等实现精准有效推送。鼓励地方和高校依托平台联合举办专场招聘活动。\n7.加强分行业分区域就业市场建设。汇聚相关部门、行业协会、社会招聘机构等多方资源，着力建设一批区域性、行业性、联盟性高校毕业生就业市场。充分发挥全国普通高校毕业生就业创业指导委员会和行业协会作用，完善“分行业就指委+分行业协会”促就业工作机制，举办系列校企对接交流活动，加大力度建设分行业就业市场。深入开展供需对接就业育人项目，搭建人才供需对接平台，推动就业与培养有机联动。\n8.鼓励中小企业更多吸纳高校毕业生。各地教育部门要配合本地相关部门落实吸纳就业补贴、社会保险补贴、税费减免等优惠政策，支持中小企业开发创造更多适合高校毕业生的就业岗位。各地各高校要加大民营企业、中小企业招聘推介力度，为企业进校招聘提供便利，引导更多毕业生到民营企业、中小企业就业。会同有关部门持续举办“百城万企——民企高校携手促就业”“全国中小企业网上百日招聘高校毕业生”“全国民营企业招聘月”等活动，为中小企业招聘高校毕业生搭建平台。\n9.支持灵活就业和自主创业。各地各高校要充分挖掘新产业、新业态、新模式带动就业潜力，引导毕业生发挥专业所长，在创意经济、数字经济、平台经济等多领域灵活就业。配合有关部门落实灵活就业社会保障政策，切实维护高校毕业生合法权益。积极鼓励和支持高校毕业生自主创业，落实创业支持政策，在资金、场地等方面向毕业生创业者倾斜，为高校毕业生创新创业孵化、成果转化等提供服务。\n三、充分发挥政策性岗位吸纳作用\n10.优化政策性岗位招录安排。各地要积极拓展政策性岗位资源，稳定并适度扩大招录高校毕业生规模。各地教育部门要加强与相关部门协调配合，统筹推动尽早安排党政机关、事业单位、国有企业等招考和各类升学考试、职业资格考试，加快政策性岗位招录进程，为高校毕业生求职留出充足时间。发挥国有企业示范作用，办好第五季“国聘行动”。加大科研助理岗位开发力度，落实相关配套措施。\n11.大力挖掘基层就业空间。各地教育部门要积极配合有关部门组织实施好“特岗计划”“三支一扶”“西部计划”等基层就业项目，拓展实施“城乡社区专项计划”“大学生乡村医生专项计划”。支持各地围绕落实推进乡村振兴战略，深入挖掘基层医疗卫生、养老服务、社会工作、司法辅助等就业机会，扩大实施地方基层项目。鼓励各地健全支持激励体系，出台更多地方优惠政策，吸引更多毕业生到中西部地区、东北地区、艰苦边远地区和基层一线就业创业。\n12.积极配合做好大学生征兵工作。各地各高校要密切军地协同，加强征兵工作站建设，加大征兵宣传进校园工作力度，畅通入伍绿色通道，配合兵役机关做好兵员预征预储、高校毕业生征集等工作，进一步推进以高校毕业生为重点的精准征集。各地教育部门要研制细化方案和实施办法，按照有关规定落实好退役后复学、升学、学费资助等优惠政策，积极鼓励高校毕业生应征入伍。\n四、推进构建高质量就业指导服务体系\n13.加强就业教育和观念引导。将就业教育和观念引导作为“三全育人”的重要内容，推动就业教育与思政教育、专业教育深度融合，在专业课教学和实习实践等育人环节强化就业教育引导。深入开展“就业育人”主题教育活动，引导毕业生树立正确的成才观、职业观、就业观，客观看待个人条件和社会需求，从实际出发选择职业和工作岗位，主动投身艰苦地区、重点领域等国家需要的地方建功立业。开展基层就业卓越教师和毕业生推荐，做好先进典型选树和系列宣讲活动。\n14.加强生涯教育和就业指导。强化大学生生涯发展与就业指导课程建设，修订完善课程教学要求。推动各高校以全覆盖、精准化、特色化为目标，将课程建设作为强化就业指导服务的重要内容，作为必修课列入教学计划，给予学时学分保障。持续办好就业指导公益直播课，提供丰富优质课程资源。遴选打造一批优秀就业指导课程和教材。加强高素质专业化教师队伍培养，打造内外互补、专兼结合的就业指导教师队伍。充分运用现代信息技术，探索建立学生成长电子档案，为学生提供个性化、精准化、便捷化的就业指导服务。\n15.办好首届全国大学生职业规划大赛。各地各高校要办好省、校两级赛事，全面提升大赛的覆盖面和实效性。鼓励将大赛内容设计同生涯发展与就业指导课程深度融合，切实增强大学生生涯规划意识，促进就业指导教师提升教学水平。鼓励将大赛与校园招聘和校企人才供需对接深度融合，引入真实职场环境，结合企业招聘要求优化赛事安排，动员更多用人单位参与大赛，帮助更多毕业生通过参赛提升职业规划和就业能力，顺利实现就业。\n16.引导强化就业实习实践。各地各高校要建立完善大学生就业实习管理制度，统筹协调就业实习与教学实习，组织引导大学生利用寒暑假时间积极参与就业实习实践。通过实习实践激发学生求职意愿、明确求职意向，帮助学生增强就业能力、获取就业机会。鼓励地方政府、用人单位与高校深化产学研合作，协同打造一批大学生就业实习基地。\n17.切实维护毕业生就业权益。积极营造平等就业环境，严格落实“三严禁”要求，各类校园招聘活动中不得设置违反国家规定的有关歧视性条款和限制性条件。加强就业安全教育和诚信教育，引导用人单位与高校毕业生及早签订就业协议书或劳动（聘用）合同并如实履约。及时发布求职就业预警信息，帮助毕业生防范求职风险。会同相关部门加强联合监管，依法严厉打击虚假招聘、售卖协议、“黑职介”“培训贷”等违法违规行为。\n五、加强重点群体就业帮扶\n18.完善精准帮扶机制。重点关注脱贫家庭、低保家庭、零就业家庭、残疾等就业困难毕业生群体，“一人一档” “一人一策”建立帮扶工作台账，优先提供指导服务、优先推荐就业岗位、优先开展培训和就业实习。落实“一对一”帮扶责任制，高校和院系领导班子成员、就业指导教师、班主任、专业教师、辅导员等要与困难学生开展结对帮扶，确保每一个困难学生都得到有效帮助。会同人力资源社会保障部门持续做好离校未就业毕业生的跟踪帮扶和不断线服务。\n19.深入实施“宏志助航计划”。继续组织实施“中央专项彩票公益金宏志助航计划——全国高校毕业生就业能力培训项目”。各地和培训基地高校要精心组织实施，持续优化培训内容，不断提升培训实效。鼓励各地各高校配套设立省级、校级项目，扩大培训覆盖面。支持将就业能力培训与指导咨询、心理疏导、岗位推荐等统筹推进。强化培训基地管理，规范使用专项资金，试点开展项目实施效果评估。\n20.推进对口就业帮扶援助。鼓励部属高校与地方高校、东部高校与西部高校、典型经验高校与基础薄弱高校结对开展就业帮扶，推动区域间、校际间就业经验交流、就业渠道互补、就业资源共享。加强区域统筹协调，调配更多岗位资源，为基础薄弱地区和高校提供就业帮扶援助。充分发挥工会、共青团、妇联、残联等群团组织和社会公益组织作用，为困难群体毕业生提供有温度的就业服务。\n六、完善就业监测与评价反馈机制\n21.加强就业数据监测。各地各高校要认真落实毕业去向登记制度，准确把握就业监测指标内涵，严格审核毕业生就业信息和就业材料，确保就业数据真实准确。完善毕业生就业状况布点监测机制。加强就业监测工作业务培训，提升就业监测工作质量、时效和规范化水平。严格落实就业监测工作“四不准”“三不得”要求，分级开展就业工作核查，严格执行就业监测工作违规处理办法，对违反相关规定的高校和相关人员，依规依纪严肃追责问责。\n22.推进就业工作综合评价。进一步完善高校毕业生就业工作综合评价指标体系，推动各地和高校破除单一评价导向，深化就业工作评价改革，促进高校就业工作制度化、规范化。选树一批全国高校毕业生就业创业工作典型，加强就业工作经验交流和宣传推广，推动各地和高校全面提升就业工作能力和服务水平。加强就业工作研究，为政府宏观决策、高校深化教育教学和人才培养改革提供支撑。\n23.完善就业状况反馈机制。各地各高校要建立完善就业与招生、培养联动的有效机制，把高校毕业生就业状况作为高等教育结构调整的重要内容。引导高校重点布局社会需求强、就业前景广、人才缺口大的学科专业，及时调整或更新升级已经不适应社会需要的学科专业。持续实施高校毕业生就业去向落实率红黄牌提示制度。深入开展高校毕业生就业状况跟踪调查，把毕业生就业状况作为“双一流”建设成效评价、学科专业设置和调整评估、招生计划安排、就业工作评价等工作的重要依据。\n七、加强组织保障\n24.逐级压实工作责任。各地各高校要切实落实就业“一把手”工程，主要负责同志要亲自部署，分管负责同志要靠前指挥。要将高校毕业生就业工作纳入领导班子考核，适时开展就业工作督促检查，推动逐级落实就业工作责任。建立完善就业风险防范化解机制，确保就业安全稳定。教育部将省级人民政府及相关职能部门制定促进高校毕业生就业政策及其实施情况，纳入省级人民政府履行教育职责评价重要内容。\n25.充实就业工作机构和力量。各地各高校要认真落实就业工作机构、人员、经费、场地“四到位”要求。省级教育行政部门要加强就业部门和服务机构工作力量，给予必要的人员、经费保障。高校要加强就业指导服务机构建设，按照不低于毕业年度毕业生500:1的比例配备校级就业工作人员，鼓励在二级院系设立专职就业工作人员。加强专业化、职业化就业工作队伍建设，定期开展毕业班辅导员、就业工作人员业务培训，鼓励就业指导人员按要求参加相关职称评审。\n26.大力开展就业总结宣传。各地各高校要广泛宣传各项促就业政策措施，积极推进就业政策进园区、进企业、进高校、进社区。要大力宣传各地各高校和用人单位促就业的好经验、好做法，持续开展就业育人典型案例和毕业生就业创业典型人物总结宣传，积极营造全社会关心支持高校毕业生就业的良好氛围。各地各高校毕业生就业工作进展情况要及时报教育部。\n教育部\n2023年12月1日', '2026-04-26 01:51:56', '2026-04-26 02:11:02');
INSERT INTO `policy_data` VALUES (31, '国家发展改革委等部门关于深入实施创业带动就业示范行动 力促高校毕业生创业就业的通知', '毕业生、创业、大学生、高校毕业生、就业、培训', '来源：中国政府网\n发文机关：发展改革委 教育部 工业和信息化部 人力资源社会保障部 农业农村部 国资委 共青团中央 全国妇联\n发文字号：发改高技〔2022〕187号\n原文链接：https://www.gov.cn/zhengce/zhengceku/2022-02/11/content_5673073.htm\n\n国家发展改革委等部门关于深入实施创业带动就业示范行动 力促高校毕业生创业就业的通知\n\n发改高技〔2022〕187号\n\n各省、自治区、直辖市及计划单列市、新疆生产建设兵团发展改革委、教育厅（教委、教育局）、工业和信息化主管部门、人力资源社会保障厅（局）、农业农村（农牧）厅（局、委）、共青团委、妇联，有关中央企业：\n\n2021年，国家发展改革委会同教育部、工业和信息化部、人力资源社会保障部、农业农村部和国资委，依托大众创业万众创新示范基地（以下简称示范基地）组织实施创业带动就业示范行动（以下简称示范行动），在推动创业带动就业方面积累了有益经验、取得了积极成效。为贯彻落实中央经济工作会议精神，进一步做好高校毕业生重点群体就业工作，现就深入实施创业带动就业示范行动有关事宜通知如下。\n\n一、总体要求\n\n以习近平新时代中国特色社会主义思想为指导，全面贯彻落实党的十九大及十九届历次全会精神，聚焦高校毕业生创业就业，落细落实行动组织、政策扶持、宣传推广等工作，将《国务院办公厅关于进一步支持大学生创新创业的指导意见》（国办发〔2021〕35号）和《关于深入组织实施创业带动就业示范行动的通知》（发改办高技〔2021〕244号）的部署落到实处，发挥示范基地带动作用，力争2022年为高校毕业生提供200万个高质量就业机会，为全国做好创业带动就业工作做示范。\n\n二、突出年度重点\n\n（一）聚焦高校毕业生群体。2022届全国高校毕业生预计1076万人，他们是城镇新成长劳动力的主力军。近年来，越来越多高校毕业生投身创新创业实践，但也面临融资难、经验少、服务不到位等问题。2022年组织实施示范行动，要紧紧围绕促进高校毕业生创业就业展开，坚持问题导向，帮助高校毕业生解决创业面临的突出问题，降低创新创业门槛；供给优质创新创业教育、培训、实习等资源，帮助高校毕业生提升创业就业能力，创造更多高质量就业机会，缓解结构性就业矛盾。\n\n（二）突出创业带动就业主线。创业具有带动就业的乘数效应，是解决就业问题的渠道之一。在组织示范行动过程中，要坚持抓创业、促就业，抓创业就是要大力扶持高质量的创新创业项目，引导更多创业企业吸纳高校毕业生共同创业，为高校毕业生提供更多施展才华的机会；促就业就是要尊重高校毕业生的创业意愿，引导高校毕业生正确认识创业风险，着重帮助有强烈创业意愿、有良好项目基础的高校毕业生实现创业梦想；要多措并举、深度挖掘工作岗位，为高校毕业生特别是女性高校毕业生、零就业家庭、享受城市居民最低生活保障家庭等群体找工作创造机会。\n\n（三）做实四个专项行动任务。各示范基地要将组织示范行动与特色化功能化专业化发展紧密结合起来，与实施示范基地建设三年行动计划紧密结合起来，结合自身发展方向，从社会服务领域双创带动就业、大中小企业融通创新、精益创业带动就业等3个专项行动中选择一项承担，聚焦高校毕业生创业就业开展。此外，企业、高校示范基地均要组织实施高校毕业生创业就业校企行专项行动，要与公共就业和人才服务机构加强协调联动，探索拓展结对共建范围，将与高校示范基地探索成熟的典型做法复制推广到其他高校，在促进高校毕业生创业就业中发挥重要作用。\n\n三、做实行动方案\n\n（一）认真动员部署。层层动员部署，国家发展改革委对示范基地主管部门进行动员部署，主管部门对管理的示范基地进行动员部署，示范基地对内部参与部门进行动员部署。动员部署要将组织示范行动、力促高校毕业生创业就业的重大意义讲清楚，要将示范行动的目标任务讲清楚，要将责任分工、工作要求、时间节点等讲清楚。\n\n（二）精心谋划方案。各示范基地要根据自身承担的专项行动（企业、高校示范基地均承担两项），研究制定工作方案，明确行动目标、任务和保障措施。各主管部门要对示范基地制定的专项行动工作方案严格把关，重点评估其是否可测度可考核可实施。各示范基地要按照新要求抓紧制定专项行动工作方案，明确行动目标、任务和保障措施，2022年2月21日前报送主管部门，并通过电子邮件方式抄报国家发展改革委。2022年2月底前，各主管部门将审核通过的专项行动工作方案报送国家发展改革委，作为示范基地年度评估的依据。\n\n（三）做实过程调度。各示范基地要定期调度示范行动实施情况，掌握示范行动取得成效。主管部门要定期汇总分析示范行动开展情况，分析监测示范基地工作成效，给予针对性支持，纾解示范行动开展过程中的痛点堵点。国家发展改革委将会同有关部门，搜集汇总各示范基地创业带动就业的好经验、好做法，分析研判全国双创发展趋势。\n\n四、落实激励政策\n\n（一）落实落地普惠政策。国家发展改革委会同教育部、工业和信息化部、人力资源社会保障部、农业农村部、国资委、共青团中央、全国妇联等，建立《扶持高校毕业生创业就业普惠政策清单》（附件）。各地方发展改革委会同同级相关部门，在《扶持高校毕业生创业就业普惠政策清单》基础上，系统梳理本地区相关支持政策，补充细化形成支持示范行动实施的政策清单，2月底前印送本地区的示范基地（包括本地区由国家部门管理的示范基地），并抄送国家发展改革委。\n\n（二）强化专门政策支持。国家发展改革委会同示范基地主管部门，在2022年底前启动示范基地年度评估；对抓示范行动成效显著的示范基地，根据中央预算内投资安排，支持其承担创新创业服务平台建设项目；对真抓实干、成效显著的区域类示范基地，优先推荐纳入国务院督查激励名单。各地方发展改革委会同同级相关部门，根据本地区的实际情况，研究制定激励本地区示范基地抓示范行动组织实施的专项政策。\n\n（三）疏通政策落地堵点。示范基地指导帮助高校毕业生创业团队、吸纳高校毕业生的创业企业等落实扶持政策。国家发展改革委结合示范行动月调度系统，及时了解掌握支持政策落实落地情况。示范基地在填报月调度数据时，一并反映本地区公布政策清单中未落实的政策及原因；国家发展改革委会同有关主管部门及时研判分析，协调推动政策落实。对于多方面集中反映、具有普遍性的政策落地问题，国家发展改革委将与有关部门专题协商，纳入双创痛点堵点疏解行动，持续推动解决。\n\n五、强化宣传推广\n\n（一）用好双创活动周平台。国家发展改革委会同有关方面，重点围绕力促高校毕业生创业就业，谋划和筹备2022年全国双创活动周，营造鼓励和支持高校毕业生创业就业的良好氛围。各地发展改革委、各示范基地结合示范行动开展情况，向全国双创活动周组委会推荐优秀创业项目，汇聚资金、技术、人才等资源，加速优秀创业项目发展。各地发展改革委要围绕推动示范行动实施、力促高校毕业生创业就业，谋划和筹备本地区2022年双创活动周。\n\n（二）借力各类双创活动。充分发挥教育部中国国际“互联网+”大学生创新创业大赛，人力资源社会保障部中国创翼创业创新大赛，工业和信息化部“创客中国”中小企业创新创业大赛，农业农村部全国农村创业创新项目创意大赛，国资委中央企业熠星创新创意大赛，共青团中央创青春挑战杯系列赛事和中国青年创新创业训练营、全国妇联中国妇女创新创业大赛等重大赛事平台，为高校毕业生创新创业提供更多展示机会。\n\n（三）持续抓好媒体宣传。示范基地要及时总结组织实施专项行动中涌现出的好经验好做法，发动新闻媒体开展广泛宣传报道，推动其在更大范围内复制推广。2022年国家发展改革委将会同有关部门，组织开展示范行动专项宣传，通过系列新闻报道、专题研究报告、拍摄系列视频等多种形式，扩大示范行动影响。各地方要及时调度，广泛通过新媒体、传统媒体对示范基地组织实施专项行动开展宣传，树立更多在当地有影响力的创业带动就业典型示范项目。\n\n联 系 人：国家发展改革委高技术司 68501984\n\n电子邮箱：gjs_cyfzc@ndrc.gov.cn\n\n附件：扶持高校毕业生创业就业普惠政策清单\n\n国家发展改革委\n\n教育部\n\n工业和信息化部\n\n人力资源社会保障部\n\n农业农村部\n\n国务院国资委\n\n共青团中央\n\n全国妇联\n\n2022年2月8日', '2026-04-26 01:51:56', '2026-04-26 02:11:02');
INSERT INTO `policy_data` VALUES (32, '国务院办公厅关于进一步支持大学生创新创业的指导意见', '毕业生、创业、大学生、高校毕业生、就业、补贴、贷款、培训', '来源：中国政府网\n发布日期：2021年10月12日\n发文机关：国务院办公厅\n发文字号：国办发〔2021〕35号\n原文链接：https://www.gov.cn/zhengce/zhengceku/2021-10/12/content_5642037.htm\n\n国务院办公厅关于进一步支持\n\n大学生创新创业的指导意见\n\n国办发〔2021〕35号\n\n各省、自治区、直辖市人民政府，国务院各部委、各直属机构：\n\n纵深推进大众创业万众创新是深入实施创新驱动发展战略的重要支撑，大学生是大众创业万众创新的生力军，支持大学生创新创业具有重要意义。近年来，越来越多的大学生投身创新创业实践，但也面临融资难、经验少、服务不到位等问题。为提升大学生创新创业能力、增强创新活力，进一步支持大学生创新创业，经国务院同意，现提出以下意见。\n\n一、总体要求\n\n以习近平新时代中国特色社会主义思想为指导，深入贯彻落实党的十九大和十九届二中、三中、四中、五中全会精神，全面贯彻党的教育方针，落实立德树人根本任务，立足新发展阶段、贯彻新发展理念、构建新发展格局，坚持创新引领创业、创业带动就业，支持在校大学生提升创新创业能力，支持高校毕业生创业就业，提升人力资源素质，促进大学生全面发展，实现大学生更加充分更高质量就业。\n\n二、提升大学生创新创业能力\n\n（一）将创新创业教育贯穿人才培养全过程。深化高校创新创业教育改革，健全课堂教学、自主学习、结合实践、指导帮扶、文化引领融为一体的高校创新创业教育体系，增强大学生的创新精神、创业意识和创新创业能力。建立以创新创业为导向的新型人才培养模式，健全校校、校企、校地、校所协同的创新创业人才培养机制，打造一批创新创业教育特色示范课程。（教育部牵头，人力资源社会保障部等按职责分工负责）\n\n（二）提升教师创新创业教育教学能力。强化高校教师创新创业教育教学能力和素养培训，改革教学方法和考核方式，推动教师把国际前沿学术发展、最新研究成果和实践经验融入课堂教学。完善高校双创指导教师到行业企业挂职锻炼的保障激励政策。实施高校双创校外导师专项人才计划，探索实施驻校企业家制度，吸引更多各行各业优秀人才担任双创导师。支持建设一批双创导师培训基地，定期开展培训。（教育部牵头，人力资源社会保障部等按职责分工负责）\n\n（三）加强大学生创新创业培训。打造一批高校创新创业培训活动品牌，创新培训模式，面向大学生开展高质量、有针对性的创新创业培训，提升大学生创新创业能力。组织双创导师深入校园举办创业大讲堂，进行创业政策解读、经验分享、实践指导等。支持各类创新创业大赛对大学生创业者给予倾斜。（人力资源社会保障部、教育部等按职责分工负责）\n\n三、优化大学生创新创业环境\n\n（四）降低大学生创新创业门槛。持续提升企业开办服务能力，为大学生创业提供高效便捷的登记服务。推动众创空间、孵化器、加速器、产业园全链条发展，鼓励各类孵化器面向大学生创新创业团队开放一定比例的免费孵化空间，并将开放情况纳入国家级科技企业孵化器考核评价，降低大学生创新创业团队入驻条件。政府投资开发的孵化器等创业载体应安排30%左右的场地，免费提供给高校毕业生。有条件的地方可对高校毕业生到孵化器创业给予租金补贴。（科技部、教育部、市场监管总局等和地方各级人民政府按职责分工负责）\n\n（五）便利化服务大学生创新创业。完善科技创新资源开放共享平台，强化对大学生的技术创新服务。各地区、各高校和科研院所的实验室以及科研仪器、设施等科技创新资源可以面向大学生开放共享，提供低价、优质的专业服务，支持大学生创新创业。支持行业企业面向大学生发布企业需求清单，引导大学生精准创新创业。鼓励国有大中型企业面向高校和大学生发布技术创新需求，开展“揭榜挂帅”。（科技部、发展改革委、教育部、国资委等按职责分工负责）\n\n（六）落实大学生创新创业保障政策。落实大学生创业帮扶政策，加大对创业失败大学生的扶持力度，按规定提供就业服务、就业援助和社会救助。加强政府支持引导，发挥市场主渠道作用，鼓励有条件的地方探索建立大学生创业风险救助机制，可采取创业风险补贴、商业险保费补助等方式予以支持，积极研究更加精准、有效的帮扶措施，及时总结经验、适时推广。毕业后创业的大学生可按规定缴纳“五险一金”，减少大学生创业的后顾之忧。（人力资源社会保障部、教育部、财政部、民政部、医保局等和地方各级人民政府按职责分工负责）\n\n四、加强大学生创新创业服务平台建设\n\n（七）建强高校创新创业实践平台。充分发挥大学科技园、大学生创业园、大学生创客空间等校内创新创业实践平台作用，面向在校大学生免费开放，开展专业化孵化服务。结合学校学科专业特色优势，联合有关行业企业建设一批校外大学生双创实践教学基地，深入实施大学生创新创业训练计划。（教育部、科技部、人力资源社会保障部等按职责分工负责）\n\n（八）提升大众创业万众创新示范基地带动作用。加强双创示范基地建设，深入实施创业就业“校企行”专项行动，推动企业示范基地和高校示范基地结对共建、建立稳定合作关系。指导高校示范基地所在城市主动规划和布局高校周边产业，积极承接大学生创新成果和人才等要素，打造“城校共生”的创新创业生态。推动中央企业、科研院所和相关公共服务机构利用自身技术、人才、场地、资本等优势，为大学生建设集研发、孵化、投资等于一体的创业创新培育中心、互联网双创平台、孵化器和科技产业园区。（发展改革委、教育部、科技部、国资委等按职责分工负责）\n\n五、推动落实大学生创新创业财税扶持政策\n\n（九）继续加大对高校创新创业教育的支持力度。在现有基础上，加大教育部中央彩票公益金大学生创新创业教育发展资金支持力度。加大中央高校教育教学改革专项资金支持力度，将创新创业教育和大学生创新创业情况作为资金分配重要因素。（财政部、教育部等按职责分工负责）\n\n（十）落实落细减税降费政策。高校毕业生在毕业年度内从事个体经营，符合规定条件的，在3年内按一定限额依次扣减其当年实际应缴纳的增值税、城市维护建设税、教育费附加、地方教育附加和个人所得税；对月销售额15万元以下的小规模纳税人免征增值税，对小微企业和个体工商户按规定减免所得税。对创业投资企业、天使投资人投资于未上市的中小高新技术企业以及种子期、初创期科技型企业的投资额，按规定抵扣所得税应纳税所得额。对国家级、省级科技企业孵化器和大学科技园以及国家备案众创空间按规定免征增值税、房产税、城镇土地使用税。做好纳税服务，建立对接机制，强化精准支持。（财政部、税务总局等按职责分工负责）\n\n六、加强对大学生创新创业的金融政策支持\n\n（十一）落实普惠金融政策。鼓励金融机构按照市场化、商业可持续原则对大学生创业项目提供金融服务，解决大学生创业融资难题。落实创业担保贷款政策及贴息政策，将高校毕业生个人最高贷款额度提高至20万元，对10万元以下贷款、获得设区的市级以上荣誉的高校毕业生创业者免除反担保要求；对高校毕业生设立的符合条件的小微企业，最高贷款额度提高至300万元；降低贷款利率，简化贷款申报审核流程，提高贷款便利性，支持符合条件的高校毕业生创业就业。鼓励和引导金融机构加快产品和服务创新，为符合条件的大学生创业项目提供金融服务。（财政部、人力资源社会保障部、人民银行、银保监会等按职责分工负责）\n\n（十二）引导社会资本支持大学生创新创业。充分发挥社会资本作用，以市场化机制促进社会资源与大学生创新创业需求更好对接，引导创新创业平台投资基金和社会资本参与大学生创业项目早期投资与投智，助力大学生创新创业项目健康成长。加快发展天使投资，培育一批天使投资人和创业投资机构。发挥财政政策作用，落实税收政策，支持天使投资、创业投资发展，推动大学生创新创业。（发展改革委、财政部、税务总局、证监会等按职责分工负责）\n\n七、促进大学生创新创业成果转化\n\n（十三）完善成果转化机制。研究设立大学生创新创业成果转化服务机构，建立相关成果与行业产业对接长效机制，促进大学生创新创业成果在有关行业企业推广应用。做好大学生创新项目的知识产权确权、保护等工作，强化激励导向，加快落实以增加知识价值为导向的分配政策，落实成果转化奖励和收益分配办法。加强面向大学生的科技成果转化培训课程建设。（科技部、教育部、知识产权局等按职责分工负责）\n\n（十四）强化成果转化服务。推动地方、企业和大学生创新创业团队加强合作对接，拓宽成果转化渠道，为创新成果转化和创业项目落地提供帮助。鼓励国有大中型企业和产教融合型企业利用孵化器、产业园等平台，支持高校科技成果转化，促进高校科技成果和大学生创新创业项目落地发展。汇集政府、企业、高校及社会资源，加强对中国国际“互联网+”大学生创新创业大赛中涌现的优秀创新创业项目的后续跟踪支持，落实科技成果转化相关税收优惠政策，推动一批大赛优秀项目落地，支持获奖项目成果转化，形成大学生创新创业示范效应。（教育部、科技部、发展改革委、财政部、国资委、税务总局等按职责分工负责）\n\n八、办好中国国际“互联网+”大学生创新创业大赛\n\n（十五）完善大赛可持续发展机制。鼓励省级人民政府积极承办大赛，压实主办职责，进一步加强组织领导和综合协调，落实配套支持政策和条件保障。坚持政府引导、公益支持，支持行业企业深化赛事合作，拓宽办赛资金筹措渠道，适当增加大赛冠名赞助经费额度。充分利用市场化方式，研究推动中央企业、社会资本发起成立中国国际“互联网+”大学生创新创业大赛项目专项发展基金。（教育部、国资委、证监会、建设银行等按职责分工负责）\n\n（十六）打造创新创业大赛品牌。强化大赛创新创业教育实践平台作用，鼓励各学段学生积极参赛。坚持以赛促教、以赛促学、以赛促创，丰富竞赛形式和内容。建立健全中国国际“互联网+”大学生创新创业大赛与各级各类创新创业比赛联动机制，推进大赛国际化进程，搭建全球性创新创业竞赛平台，深化创新创业教育国际交流合作。（教育部等按职责分工负责）\n\n九、加强大学生创新创业信息服务\n\n（十七）建立大学生创新创业信息服务平台。汇集创新创业帮扶政策、产业激励政策和全国创新创业教育优质资源，加强信息资源整合，做好国家和地方的政策发布、解读等工作。及时收集国家、区域、行业需求，为大学生精准推送行业和市场动向等信息。加强对创新创业大学生和项目的跟踪、服务，畅通供需对接渠道，支持各地积极举办大学生创新创业项目需求与投融资对接会。（教育部、发展改革委、人力资源社会保障部等按职责分工负责）\n\n（十八）加强宣传引导。大力宣传加强高校创新创业教育、促进大学生创新创业的必要性、重要性。及时总结推广各地区、各高校的好经验好做法，选树大学生创新创业成功典型，丰富宣传形式，培育创客文化，营造敢为人先、宽容失败的环境，形成支持大学生创新创业的社会氛围。做好政策宣传宣讲，推动大学生用足用好税费减免、企业登记等支持政策。（教育部、中央宣传部牵头，地方各级人民政府、各有关部门按职责分工负责）\n\n各地区、各有关部门要认真贯彻落实党中央、国务院决策部署，抓好本意见的贯彻落实。教育部要会同有关部门加强协调指导，督促支持大学生创新创业各项政策的落实，加强经验交流和推广。地方各级人民政府要加强组织领导，深入了解情况，优化创新创业环境，积极研究制定和落实支持大学生创新创业的政策措施，及时帮助大学生解决实际问题。\n\n国务院办公厅\n\n2021年9月22日\n\n（此件公开发布）', '2026-04-26 01:51:56', '2026-04-26 02:11:02');
INSERT INTO `policy_data` VALUES (33, '促进青年就业创业，11项举措发布', '毕业生、创业、高校毕业生、就业、自主创业、灵活就业、招聘、补贴、培训、见习、青年就业', '来源：新华社\n原文链接：https://www.gov.cn/zhengce/202406/content_6958294.htm\n\n新华社北京6月19日电（记者王聿昊、姜琳）人力资源社会保障部、教育部、财政部19日联合发布《关于做好高校毕业生等青年就业创业工作的通知》，提出11项政策举措，全力促进高校毕业生等青年就业创业。\n\n人力资源社会保障部就业促进司有关负责人介绍，通知的一大重点举措是合并实施一次性吸纳就业补贴和一次性扩岗补助政策。对招用符合条件的毕业年度高校毕业生、离校未就业高校毕业生及登记失业青年的企业，可发放一次性扩岗补助。政策执行至2025年12月31日。\n\n先进制造业是青年就业的重点行业之一，通知明确实施先进制造业青年就业行动这一举措，将开展先进制造业职业体验活动，建立先进制造业企业集群职称评审“绿色通道”等。\n\n实施百万就业见习岗位募集计划，这一举措将支持企业、政府投资项目、事业单位开展就业见习，在今明两年每年募集不少于100万个就业见习岗位。\n\n就业困难青年帮扶也有新举措。通知要求强化未就业高校毕业生实名帮扶，建立实名台账，普遍提供至少1次政策宣介、1次职业指导、3次岗位推荐及1次培训或见习机会。强化困难高校毕业生结对帮扶，及时将脱贫家庭毕业生、残疾毕业生、长期失业青年、求职补贴发放对象纳入帮扶台账，针对性提供高质量岗位信息。\n\n为进一步做好高校毕业生等青年就业创业工作，通知还提出延续实施国有企业增人增资政策、鼓励引导基层一线就业、支持自主创业和灵活就业、大规模组织招聘对接服务、强化青年求职能力训练和学徒培训、高效办成高校毕业生就业一件事、加强就业权益维护等7项举措。', '2026-04-26 01:51:56', '2026-04-26 02:11:02');
INSERT INTO `policy_data` VALUES (34, '人力资源社会保障部 教育部 财政部关于做好2025年高校毕业生等青年就业工作的通知', '毕业生、创业、大学生、高校毕业生、就业、基层就业、三支一扶、自主创业、招聘、补贴、培训、见习、青年就业', '来源：中国政府网\n发文机关：人力资源社会保障部 教育部 财政部\n发文字号：人社部发〔2025〕20号\n原文链接：https://www.gov.cn/zhengce/zhengceku/202504/content_7021064.htm\n\n人力资源社会保障部 教育部 财政部关于做好2025年高校毕业生等青年就业工作的通知\n人社部发〔2025〕20号\n各省、自治区、直辖市及新疆生产建设兵团人力资源社会保障厅（局）、教育厅（教委、教育局）、财政厅（局）： \n高校毕业生等青年是宝贵的人才资源。为深入学习贯彻习近平新时代中国特色社会主义思想，落实党的二十届三中全会、中央经济工作会议精神，以及《中共中央 国务院关于实施就业优先战略促进高质量充分就业的意见》要求，进一步挖岗位、提能力、优服务、强保障，全力以赴做好2025年高校毕业生等青年就业工作。现就有关工作通知如下。\n一、多渠道挖掘就业岗位\n（一）扩大市场化就业岗位。拓展企业就业主渠道，综合运用扩岗补助、就业困难等人员社保补贴等各类政策，激励企业吸纳高校毕业生等青年。公开本地促进青年就业政策办理流程，明确办理时限，大力推行“直补快办”、“政策计算器”等服务方式，推动各项就业政策集中兑现，提高政策落实率。组织人社专员、高校就业工作人员对接专精特新“小巨人”企业、专精特新中小企业、高新技术企业，提供就业服务，了解面向高校毕业生等青年招聘需求，促进人岗快速匹配。深化“书记校长访企拓岗”专项行动，拓展市场化岗位规模。对招用毕业年度及离校两年内未就业高校毕业生及16-24岁登记失业青年，签订劳动合同，并按规定为其足额缴纳3个月以上的失业、工伤、职工养老保险费的社会组织，参照企业享受一次性扩岗补助政策，政策执行至2025年12月31日。\n（二）拓宽基层就业空间。省级人力资源社会保障部门要建立城乡基层岗位归集发布机制，依托公共就业服务网站、市场化人力资源服务平台等，动态发布本地就业社保、医疗卫生、养老服务等城乡社区就业岗位。统筹推进“三支一扶”计划、志愿服务西部计划、农村教师特岗计划等基层服务项目，加大招募计划向脱贫地区、东北地区、边疆地区倾斜力度。\n（三）稳定公共部门岗位规模。统筹用好本地事业单位编制存量，重点面向高校、中学等教育类事业单位和基层医疗卫生机构等医疗卫生类事业单位，挖掘岗位资源，并向高校毕业生倾斜。加快事业单位招聘进度安排，8月底前完成事业单位面向2025届高校毕业生的招聘工作。稳定扩大国有企业招聘高校毕业生规模，延续实施国有企业一次性增人增资政策，政策执行至2026年12月31日。\n（四）支持青年自主创业。用好各地创业孵化载体，鼓励政府投资的孵化器放宽高校毕业生等重点群体免费入驻门槛。强化创业服务保障，将高校毕业生创业项目纳入重点孵化项目库，提供创业培训、创业指导、创业孵化、政策落实等“一条龙”服务，提升创业成功率。支持建设全国大学生创新创业成果转化中心，促进创新创业项目孵化落地。加强融资支持，遴选有资金需求、带动就业多的高校毕业生创业项目，组织“政企银担”交流活动，开展形式多样的融资对接服务。\n二、全力支持提升就业能力\n（五）实施就业能力提升“双千”计划。聚焦就业市场急需的知识和技能要求，推动在全国高校开设1000个“微专业”和1000门职业能力培训课程，重点支持开展人工智能应用赋能就业培训。指导高校组织社会需求不足相关学科专业点学生参与“微专业”或培训课程学习，优化知识和技能结构，通过考核后可获得相应学习证明。鼓励高校建立更灵活的学习制度，允许近年持续就业状况不佳相关专业学生按规定转专业或辅修其他专业。推进急需学科专业核心课程与教学内容实质性更新迭代，根据需要超常规增设一批学科专业点。\n（六）全面推开青年求职能力实训营。省级人力资源社会保障部门要加强求职能力实训师队伍建设，组织师资培训班，开办研讨交流、观摩教学等活动。积极开展青年求职能力实训，将毕业年度高校毕业生、离校未就业高校毕业生、失业青年纳入实训范围，组织企业参观、跟岗锻炼等体验活动，开展简历修改、形象礼仪等课程教学，帮助提升求职能力。\n（七）实施百万青年职业技能提升行动。引导支持广大高校毕业生等青年根据职业规划、求职意向自主参加技能培训，按规定落实职业培训补贴。2025年，力争组织100万高校毕业生等青年参加技能培训活动。聚焦高校毕业生等青年特点，加强数字人才培育，研究数字经济技能需求清单，开发一批人工智能、大数据、智能制造等领域培训项目。深化校企合作、产教融合，推行工学一体化、学徒制、项目化等培养培训模式，加强岗位核心技能、关键技术实操实训，提升高校毕业生等青年技能水平。\n（八）实施百万就业见习岗位募集计划。强化见习岗位开发，面向企业、科研院所等事业单位开发科研类、技术类、管理类岗位。强化见习规范管理，指导见习单位做好见习协议签订、带教制度落实、见习待遇保障相关工作，定期跟进检查见习单位见习人员管理、政策落实和见习实效等情况。强化见习跟踪帮扶，鼓励见习单位留用见习人员，做好见习后未留用人员后续就业帮扶。\n三、着力强化就业服务保障\n（九）做实做细高校就业指导帮扶。强化就业观念引导，增强大学生生涯规划意识，办好第二届全国大学生职业规划大赛。国家大学生就业服务平台实施“共建共享岗位精选计划”，汇集更多岗位资源。高校建立就业困难毕业生帮扶台账，发动其优先参加“宏志助航计划”。\n（十）开展公共就业服务进校园活动。3-6月，省级人力资源社会保障部门会同教育部门持续推动政策宣传、招聘服务、就业指导、创业服务、职业培训、困难帮扶等“六进”校园。充分发挥职业指导师、就业创业领域专家、人力资源经理等专业力量作用，开展多元化交流指导，组织沙龙对话、求职讲堂、就业咨询等活动。支持有条件的地方与高校合作设立就业创业指导服务站，为毕业生求职就业提供便利。\n（十一）开展百所高校人社厅局长结对帮扶活动。各省级人力资源社会保障部门会同教育部门选取3-5所就业工作任务重、压力大的高校，组织人社厅（局）长、就业局长定点联系、定期走访、定向服务。根据结对院校毕业生学历层次、技能水平、就业意愿等，针对性筛选、推送岗位信息，针对性提供职业指导、创业辅导等服务。\n（十二）实施离校未就业毕业生就业服务攻坚行动。省级人力资源社会保障部门要主动与教育部门对接，7月份完成有就业意愿的离校未就业毕业生实名信息交接。综合运用求职登记、走访摸排等方式，完善实名台账，普遍提供至少1次政策宣介、1次职业指导、3次岗位推荐及1次培训或见习机会。聚焦低保家庭、零就业家庭、防止返贫监测对象家庭、残疾等困难高校毕业生，明确专人结对帮扶，实施“一人一策”，针对性提供3-5个高质量岗位信息。\n（十三）开展“职引未来”系列招聘活动。全年接续举办百日千万招聘、全国城市联合招聘高校毕业生、民营企业招聘月、国聘行动、人力资源市场高校毕业生就业服务专项行动、24365线上校园招聘等专项活动，丰富行业企业专场、直播带岗等特色招聘，保持市场热度。高校毕业生集中的城市每周至少举办1次专业性招聘，每月至少举办1次综合性招聘，重点面向三四线城市倾斜岗位资源。要强化做好现场招聘会安全管理工作的责任意识和底线思维，严格落实属地管理责任，建立完善风险防控机制，确保各类现场招聘会安全。\n（十四）建立失业青年常态化帮扶机制。全年开放未就业毕业生求职登记小程序，畅通本地线上线下求助渠道，允许失业青年在户籍地、常住地、求职地进行求职登记。加强就业转失业青年摸排，掌握其就业失业状态，持续开展联系服务。加大异地求职服务力度，依托零工市场（零工驿站）、家门口就业服务站等现有资源，建设一批青年就业驿站，为异地求职的高校毕业生等青年提供政策解读、职业指导、招聘信息等“一站式”服务。\n四、加力营造就业良好环境\n（十五）加强招聘信息审核。指导用人单位和人力资源服务机构依法依规设置招聘条件，不得发布性别、民族等歧视性信息，不得发布虚假和欺诈等非法信息，不得发布与岗位职责适配性无关的限制性条件。加强公共就业服务活动和各类校园招聘活动参与企业资质及岗位信息审核，避免不合理招聘信息。\n（十六）维护人力资源市场秩序。开展清理整顿人力资源市场秩序专项行动，依法打击培训贷、付费实习、虚假招聘等违法行为，及时查处滥用试用期、不签订劳动合同等乱象。加强侵权典型案例警示教育，发布传销、借贷、“黑职介”等招聘求职陷阱提示，加大防电信诈骗宣传，帮助高校毕业生等青年提升风险防范意识。用好12333人力资源社会保障服务热线，及时受理、查处高校毕业生等青年就业创业过程中的侵权线索，维护合法就业权益。\n（十七）强化宣传引导。开展高校毕业生等青年就业创业政策服务宣传，综合新闻媒体、微博微信、广播电视等渠道，制作发布本地区政策清单、服务项目清单、招聘活动清单，提升政策服务知晓度。开展典型宣传，积极选树服务重大战略、扎根城乡基层、投身西部地区等青年就业典型，组织好“最美高校毕业生”、“平凡岗位精彩人生”、“永远跟党走到祖国需要的地方去”、“劳模工匠进校园”、“基层就业卓越奖学（教）金”等人物事迹宣传，引导高校毕业生等青年将职业选择融入国家建设发展。\n各地要切实提高思想认识，把促进高校毕业生等青年就业作为重大政治责任，细化工作方案，明确职责分工，落实工作要求。要加强协同配合，人力资源社会保障部门要加强工作统筹协调，建立工作调度机制，落实各项就业帮扶政策措施，确保各项任务落实落地；教育部门要加强高校毕业生就业指导服务，配合相关部门落实各项促就业政策；财政部门要统筹各类资金渠道，对高校毕业生等青年就业工作予以支持。\n人力资源社会保障部\n教育部\n财政部\n2025年4月17日', '2026-04-26 02:11:02', '2026-04-26 02:11:02');
INSERT INTO `policy_data` VALUES (35, '就业创业获真金白银支持', '毕业生、创业、大学生、高校毕业生、就业、基层就业、三支一扶、招聘、补贴、贷款、见习', '来源：经济日报\n原文链接：https://www.gov.cn/zhengce/202404/content_6942996.htm\n\n近期，国务院新闻办公室举行新闻发布会，介绍近期投资、财政、金融有关数据及政策情况。发布会信息显示，2024年中央财政安排就业补助资金预算667亿元，支持落实就业创业扶持政策。\n财政部副部长廖岷表示，党中央、国务院高度重视就业工作，强调把稳就业提高到战略高度通盘考虑。有就业才有收入，有收入才有消费，有消费才有内需。财政部将继续立足财政职能，推动落实就业优先战略，强化对高校毕业生、农民工、就业困难人员等重点群体的就业扶持。\n就业，始终是关系国计民生的重要课题。据悉，今年财政部将重点围绕以下几个方面做好相关工作：\n一是更加突出就业优先导向。坚持把稳定和扩大就业作为经济社会发展的优先目标，在制定财税政策时更加注重促进就业。\n二是支持经营主体稳定就业岗位。主要是落实好结构性减税降费政策，延续实施阶段性降低失业、工伤保险费率政策，着力降低经营主体成本负担。继续实施失业保险稳岗返还政策，对不裁员、少裁员的企业按比例返还上一年度实际缴纳的失业保险费，支持企业稳定岗位、吸纳就业。\n三是助力发挥创业带动就业作用。对符合条件的重点群体和吸纳其就业的小微企业申请的创业担保贷款，财政部门给予贷款贴息。引导政府性融资担保机构加大对劳动密集型企业的倾斜。“我们做了一个内部测算，预计2024年可撬动1.3万亿元新增贷款，稳定就业岗位超过1200万个，拉动新增就业超过60万人。”廖岷表示，将支持高校加强创新创业教育，提升大学生创新创业能力；对符合条件的高校毕业生、就业困难人员首次创办小微企业或者从事个体经营的给予创业补贴。\n四是继续聚焦重点群体就业。鼓励企业加大招聘力度，对吸纳重点群体就业的给予社会保险补贴，对招聘符合条件的高校毕业生就业见习的给予就业见习补贴。挖潜更多基层就业机会和岗位，实施西部计划、“三支一扶”计划、“特岗计划”、大学生乡村医生专项计划等，财政部门都将给予支持，鼓励引导高校毕业生到基层就业。同时，对符合条件的高校应届毕业生到艰苦边远等地区就业的，其学费实行补偿代偿。此外，持续为脱贫人口、农村低收入人口、残疾人等提供分类就业帮扶，巩固脱贫成果。\n“就业作为经济增长和民生改善的关键一环，其重要性不言而喻。在稳就业当中，政府资金的支持和带动作用不可或缺。”中国社会科学院财经战略研究院财政研究室主任何代欣在接受记者采访时表示，安排就业补助资金的核心是要贯彻落实党中央关于就业优先的战略部署。\n近年来，财政资金加大力度支持落实就业优先政策。过去3年来，中央财政资金在就业补助方面持续稳定在600亿元以上，显示出对就业优先政策的有力支持和保障。何代欣认为，就业补助资金的增加，说明中央对就业问题的高度重视，同时体现了中央通过财政支出的方式加力稳就业、促就业和扩就业的决心，“目前来看，就业补助资金的作用方式更加具体，一系列配套措施也在落实当中，各地因地制宜的办法不断推出，有利于进一步发挥政策效用和实现政策目标”。\n中央经济工作会议要求，2024年要继续实施积极的财政政策，适度加力、提质增效；更加突出就业优先导向，确保重点群体就业稳定。随着一系列稳就业措施的实施，今年的就业市场有望为广大劳动者带来更多的就业机会，提供更好的就业服务，迎来更加积极的变化。（记者 苏瑞淇）', '2026-04-26 02:11:02', '2026-04-26 02:11:02');
INSERT INTO `policy_data` VALUES (36, '教育部办公厅关于印发全国普通高校毕业生就业创业指导委员会章程的通知', '毕业生、创业、大学生、高校毕业生、就业、招聘、培训、见习', '来源：中国政府网\n发文机关：教育部办公厅\n发文字号：教学厅函〔2021〕31号\n原文链接：https://www.gov.cn/zhengce/zhengceku/2021-11/04/content_5648774.htm\n\n教育部办公厅关于印发全国普通高校毕业生就业创业指导委员会章程的通知\n\n教学厅函〔2021〕31号\n\n各省、自治区、直辖市教育厅（教委），新疆生产建设兵团教育局，部属各高等学校、部省合建各高等学校，2021—2025年全国普通高校毕业生就业创业指导委员会：\n\n为做好2021—2025年全国普通高校毕业生就业创业指导委员会各项工作，建立科学合理、规范有效的工作机制，特制定《全国普通高校毕业生就业创业指导委员会章程》。现予印发，请遵照执行。\n\n教育部办公厅\n\n2021年10月13日\n\n全国普通高校毕业生就业创业指导委员会章程\n\n第一章 总则\n\n第一条 全国普通高校毕业生就业创业指导委员会（以下简称就指委）是由教育部组建，开展高等学校毕业生就业创业工作的全国性、非营利性专家组织，具有非常设机构性质。\n\n第二条 就指委以习近平新时代中国特色社会主义思想为指导，落实党中央、国务院关于高校毕业生就业创业工作的重要决策部署，坚持就业优先政策，健全高校毕业生就业支持体系，广泛汇聚市场化社会化就业创业资源，多渠道拓展就业空间，促进高校毕业生更加充分更高质量就业。\n\n第二章 职责\n\n第三条 就指委接受教育部委托，开展大学生就业创业研究、咨询、指导、服务和评估等工作。具体任务如下：\n\n（一）开展大学生就业创业研究和政策咨询。对产业结构变化、就业市场需求、新就业形态、人才供给情况等与高校毕业生就业创业相关课题进行宏观研究，研判国内外就业形势，编写发布高校毕业生就业供需研究报告，为大学生就业创业政策制定和相关行业单位人力资源发展提供咨询建议。\n\n（二）搭建就业创业供需对接平台。重点面向国家战略需求共同开展就业教育引导，推动供需对接、校企合作、学职衔接，建立大学生就业实习见习基地和就业创业服务平台，组织供需双方举办重点领域、重点行业、重点区域和中小微企业等专场招聘会。\n\n（三）推动大学生职业生涯教育。研制相关学科专业大学生学业与职业指南，编写大学生职业发展与就业指导教材，推进优质教学资源开放共享。\n\n（四）推动大学生就业创业队伍建设。开展大学生就业创业工作队伍保障机制研究、能力培训、学术研讨等，推动学校与用人单位、学校与学校之间相关工作交流，参与遴选就业创业工作先进典型，开展多种形式宣传推广。\n\n（五）开展就业工作调查督查。协助教育部开展高校毕业生就业形势调查、就业状况跟踪调查和专项督查，分层分类建立高校就业评价指标体系，健全毕业生就业状况对高校招生、学科专业设置和人才培养的反馈联动机制。\n\n（六）承担教育部委托的其他与高校毕业生就业创业相关的工作。\n\n第三章 组织机构\n\n第四条 就指委设主任委员1人，常务副主任委员1—2人。结合国民经济行业分类设立分行业就指委（简称行业就指委），根据专项业务设置若干专家组，分别设主任委员（组长）1人，副主任委员（副组长）若干人。\n\n第五条 就指委秘书处设在教育部高校学生司，设秘书长1人，副秘书长2—3人。各行业就指委结合实际建立组织体系，设立秘书处，经所在机构委员讨论同意后，报全国就指委秘书处备案。专家组可参照执行。\n\n第六条 凡符合委员基本条件、热心毕业生就业创业工作的人选每年可通过个人申请或行业就指委（专家组）推荐，吸收为专家库成员。表现优异的可按规定流程增补为委员。\n\n第四章 委员\n\n第七条 就指委委员由机关、高校、行业协会、企事业单位的专家构成，由教育部选聘，实行动态调整机制。\n\n第八条 委员基本条件：\n\n（一）政治立场坚定，遵纪守法，能够全面贯彻党的教育方针政策，拥护本章程，自愿加入就指委。\n\n（二）熟悉人力资源市场、行业产业发展或高等教育规律，热心大学生就业创业工作，能够保证参与就指委工作时间。\n\n（三）委员一般代表所在单位，在任期内若因调离、退休等原因离开单位的，应由继任者递补；在本单位调岗且工作内容仍与就业创业领域相关的则不受此影响。\n\n第九条 委员权利：\n\n（一）出席就指委会议，行使审议权和表决权；\n\n（二）推荐就指委委员；\n\n（三）参加高校毕业生就业创业研究、咨询、指导、服务和评估等活动；\n\n（四）获得就指委服务，依照规定查阅相关资料和数据；\n\n（五）获得人才供需对接信息、实现更高效供需匹配；\n\n（六）对高校毕业生就业创业工作提出意见建议。\n\n第十条 委员义务：\n\n（一）遵守本章程，执行就指委决议，以严谨、科学、负责的态度，按时完成就指委安排的工作任务；\n\n（二）廉洁自律，自觉抵制不正之风，不得以就指委或委员身份从事任何商业活动以及影响公正的行为；\n\n（三）严格遵守保密纪律，不得泄露工作中接触到的国家秘密和其他需要保密的数据信息；\n\n（四）所有成员使用就指委委员身份出版作品、申报项目等，须提前向所在就指委的秘书处报备，经同意后方可进行；\n\n（五）自觉维护就指委合法权益，如实反映有关情况。\n\n第十一条 委员调整：\n\n（一）有下列情形之一的委员原则上不再聘任：\n\n1. 被依法追究刑事责任的；\n\n2. 受到开除党籍、开除公职等党纪、政务处分的；\n\n3. 利用就指委委员身份或影响牟取个人、小团体和特定关系人利益的；\n\n4. 未履行委员职责，一个自然年内未参加就指委任何活动或连续两年表现较差的；\n\n5. 因其他原因不适合担任委员职务或主动提出辞呈的。\n\n（二）根据工作需要增补聘任新委员：\n\n1. 增补的委员需符合委员选聘基本条件，一般从专家库成员中遴选；\n\n2. 增补的委员聘期至本届就指委聘期届满止；\n\n3. 增补工作由就指委秘书处负责。\n\n第十二条 全国及行业就指委（专家组）主任委员职责：\n\n（一）负责就指委建设及日常管理工作；\n\n（二）负责召集并主持就指委会议，确定会议议题；\n\n（三）组织起草就指委年度工作计划、总结等，统筹各项工作推进；\n\n（四）每年对委员工作情况作出评价（优良中差），并提出委员调整建议；\n\n（五）指导秘书长开展工作；\n\n（六）就指委赋予的其他职责。\n\n如主任委员因故不能履行上述职责，可委托常务副主任委员或一位副主任委员代为履行。\n\n第十三条 全国及行业就指委秘书长职责：\n\n（一）主持秘书处日常工作；\n\n（二）筹备就指委相关会议，组织落实相关任务；\n\n（三）在主任委员指导下开展就指委相关工作。\n\n第五章 工作制度\n\n第十四条 建立就指委全体委员会议制度。原则上每五年召开一次，由主任委员召集、全体委员参加。\n\n（一）制定修改《章程》；\n\n（二）审议工作报告和财务报告；\n\n（三）讨论机构设置、运行机制；\n\n（四）改选新一届就指委委员；\n\n（五）决定就指委其他重大事宜。\n\n大会须有2/3以上的委员出席方能召开，会议决议须经到会委员半数以上表决通过方能生效。\n\n第十五条 建立就指委联席会议制度。一般由就指委秘书长召集，就指委主任、副主任（含常务）委员以及行业就指委（专家组）主任委员参会，必要时可变动日程或召开扩大会。联席会议职权有：\n\n（一）研究推进重点工作；\n\n（二）研究拟定就指委规划、工作计划和总结报告等；\n\n（三）进行委员届中调整；\n\n（四）讨论决定其他重要事项。\n\n各行业就指委、专家组可参照实施。\n\n第十六条 建立行业就指委（专家组）全体委员会议制度，原则上每年召开一次，由主任委员召集。研究行业发展动态，制定相关工作计划，推进重点任务，讨论需要全体委员议定的重要事项等。\n\n第十七条 建立秘书长工作会议制度，原则上一个季度召开一次，由全国就指委秘书长召集，各行业就指委（专家组）秘书长参会。听取行业就指委（专家组）本期重点工作安排，沟通推进需要协调解决的各类事项。\n\n第十八条 各行业就指委、专家组定期报送工作进展情况。研究形成的重大行业标准、政策建议、分析报告等，组织开展的评比、培训、挂牌等，须报请全国就指委秘书处同意后实施，相关进展情况应及时报告。\n\n第六章 工作支持\n\n第十九条 各省级教育主管部门、高等学校以及委员所在单位应通过多种途径支持就指委工作。各行业就指委（专家组）主任委员所在单位应为就指委日常工作开展，提供适量经费和保障支撑。\n\n就指委可以项目形式为行业就指委（专家组）提供一定经费。全国及行业就指委（专家组）可以接受社会各界赞助，但应遵守国家有关规定，并不得影响公正履职。\n\n第七章 附则\n\n第二十条 各行业就指委、专家组可依据本章程制订工作细则。\n\n第二十一条 本章程自公布之日起施行，由就指委秘书处负责解释。', '2026-04-26 02:11:02', '2026-04-26 02:11:02');
INSERT INTO `policy_data` VALUES (37, '关于开展“科技创业带动高质量就业行动”的通知', '毕业生、创业、大学生、高校毕业生、就业、招聘、补贴、培训、见习', '来源：中国政府网\n发文机关：科技部\n发文字号：国科火字〔2020〕109号\n原文链接：https://www.gov.cn/zhengce/zhengceku/2020-07/03/content_5523777.htm\n\n关于开展“科技创业带动高质量就业行动”的通知\n\n国科火字〔2020〕109号\n\n各省、自治区、直辖市及计划单列市科技厅（委、局），新疆生产建设兵团科技局，各国家高新区管委会，各有关单位：\n\n为贯彻落实党中央、国务院“六稳”“六保”精神，推动高质量创新创业特别是促进大学生就业创业，按照科技部党组的要求，火炬中心决定联合地方开展“科技创业带动高质量就业行动”。现将相关事项通知如下：\n\n一、挖掘需求推动大学生就业。选择有条件的地区，火炬中心联合地方科技管理部门、国家高新区开展“科技创业带动高质量就业行动（大学生招聘专场）”，深度挖掘在孵企业、孵化机构、创业企业的大学生招聘需求，提出有针对性的岗位面向大学生推介，促进高校大学生就业。\n\n二、营造环境促进大学生创业。发动大学科技园、科技企业孵化器、众创空间、创业投资机构等，为高校毕业生开展创新创业服务，采取减免房租、创业资助、带薪实习等方式吸引高校毕业人才进入孵化机构见习创业或实习，支持大学生创业，鼓励各地方政府根据解决大学生创业就业情况给予创业孵化机构一定补贴。\n\n三、开发科研助理岗位促大学生就业。鼓励各地方科技管理部门、国家高新区组织引导高等学校、科研院所、科技企业、创新平台等单位积极开发科研助理岗位，吸纳高校毕业生就业，建立完善项目承担单位科研助理队伍建设的长效机制，加强对科研助理岗位高校毕业生就业服务。\n\n四、举办双创活动提振创业就业信心。全国双创周期间，筛选一批在创业带动就业工作中有特色、有亮点的科技企业孵化器、众创空间等在主会场集中展示，通过创业分享、招聘活动、创新创业成果展示以及开展由大学生、留学生创业企业参加的创业大赛、项目对接、项目路演、线上培训等系列活动，提振全社会创业就业信心。\n\n各地方要高度重视科技创业带动高质量就业工作，努力探索，先行先试，做好典型经验的宣传和推广。请各地方科技管理部门、国家高新区把推进科技创业带动高质量就业工作的相关大学生招聘、科研助理岗位设置等情况及时报送我中心。\n\n联系人：徐示波 陈晴\n\n联系电话：010-88656201 6200\n\n科技部火炬中心\n\n2020年6月19日', '2026-04-26 02:11:02', '2026-04-26 02:11:02');
